// Mock Fetch Function with simulated filter logic
export const getDashboardData = (filter: FilterState): Promise<DashboardData> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      // Clone base data to modify based on filters
      let kpi = [...kpiBase];
      let revenue = [...revenueBase];
      let funnel = [...funnelBase];

      // Simulate filter logic
      if (filter.period === '30days') {
        kpi = kpi.map(item => ({ ...item, value: item.value * 4, changeValue: 'N/A' }));
        funnel = funnel.map(item => ({ ...item, count: item.count * 3.5 }));
        revenue = revenue.map(item => ({ ...item, completed: item.completed * 2, pending: item.pending * 2 }));
      }

      if (filter.status === 'sold') {
         // Dummy logic: reduce pending deals
         kpi[1].value = 10; 
         kpi[1].changeType = 'negative';
      }

      resolve({
        kpi,
        funnel,
        leadSources: sourceBase,
        revenue,
        inventory: inventoryBase
      });
    }, 600); // 600ms delay
  });
};

