// --- Customized Tooltip ---
const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white p-3 border border-slate-200 shadow-lg rounded-lg text-sm">
        <p className="font-semibold text-slate-700 mb-1">{label ? label : payload[0].payload.name || payload[0].name}</p>
        {payload.map((entry: any, index: number) => (
          <div key={index} className="flex items-center gap-2" style={{ color: entry.color }}>
            <span className="w-2 h-2 rounded-full" style={{ backgroundColor: entry.color }}></span>
            <span>{entry.name}: </span>
            <span className="font-bold">
              {typeof entry.value === 'number' && entry.value > 1000 
                ? formatCurrencyTy(entry.value) 
                : formatNumber(entry.value)}
            </span>
          </div>
        ))}
      </div>
    );
  }
  return null;
};

// --- Funnel Chart ---
export const LeadFunnelChart = ({ data }: { data: FunnelStage[] }) => {
  return (
    <ResponsiveContainer width="100%" height={300}>
      <FunnelChart>
        <RechartsTooltip content={<CustomTooltip />} />
        <Funnel
          dataKey="count"
          data={data}
          isAnimationActive
        >
          <LabelList 
            position="right" 
            fill="#0f172a" 
            stroke="none" 
            dataKey="stage" 
            content={(props: any) => {
                const { x, y, width, value, index } = props;
                const item = data[index];
                const percentage = index === 0 ? 100 : Math.round((item.count / data[0].count) * 100);

                return (
                    <text x={x + width + 10} y={y + 20} fill="#64748b" className="text-xs font-medium">
                        <tspan x={x + width + 10} dy="0" className="text-slate-800 font-bold">{value}</tspan>
                        <tspan x={x + width + 10} dy="1.2em" className="text-slate-500 text-xs">{formatNumber(item.count)} ({percentage}%)</tspan>
                    </text>
                )
            }}
          />
        </Funnel>
      </FunnelChart>
    </ResponsiveContainer>
  );
};

// --- Pie Chart ---
export const SourcePieChart = ({ data, onSelect }: { data: LeadSource[], onSelect: (name: string) => void }) => {
  return (
    <ResponsiveContainer width="100%" height={220}>
      <PieChart>
        <Pie
          data={data}
          cx="50%"
          cy="50%"
          innerRadius={50}
          outerRadius={80}
          paddingAngle={2}
          dataKey="value"
          onClick={(data) => onSelect(data.name)}
          cursor="pointer"
        >
          {data.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={entry.color} stroke="none" />
          ))}
        </Pie>
        <RechartsTooltip />
        <Legend 
            layout="vertical" 
            verticalAlign="middle" 
            align="right"
            iconType="circle"
            formatter={(value, entry: any) => <span className="text-xs text-slate-600 font-medium ml-1">{value} ({Math.round((entry.payload.percent || 0) * 100)}%)</span>}
        />
      </PieChart>
    </ResponsiveContainer>
  );
};

