export const getDashboardData = (filter: FilterState): Promise<DashboardData> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      let kpi = [...kpiBase];
      let revenue = [...revenueBase];
      let funnel = [...funnelBase];

      if (filter.period === '30days') {
        // Scale up for 30 days view roughly x4
        kpi = kpi.map(item => ({ 
            ...item, 
            value: item.id === '5' || item.id === '6' ? item.value : item.value * 3.5 
        }));
        funnel = funnel.map(item => ({ ...item, count: Math.round(item.count * 3.5) }));
        revenue = revenue.map(item => ({ 
            ...item, 
            completed: item.completed * 1.5, // Just visual change
            pending: item.pending * 1.5 
        }));
      }

      if (filter.status === 'sold') {
         kpi[1].value = 12; // Fewer pending
      }

      resolve({
        kpi,
        funnel,
        leadSources: sourceBase,
        revenue,
        inventory: inventoryBase
      });
    }, 800);
  });
};

import React from 'react';
import {
  ResponsiveContainer,
  FunnelChart,
  Funnel,
  LabelList,
  Tooltip as RechartsTooltip,
  PieChart,
  Pie,
  Cell,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Legend,
