  Bar,
} from 'recharts';
import { FunnelStage, LeadSource, RevenueData, InventoryCategory } from '../types';
import { formatNumber, formatCurrencyTy } from '../utils';

// --- Customized Tooltip ---
const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-sm p-3 border border-slate-200 shadow-xl rounded-lg text-sm ring-1 ring-slate-100">
        <p className="font-semibold text-slate-800 mb-2 border-b border-slate-100 pb-1">{label ? label : payload[0].payload.name || payload[0].name}</p>
        {payload.map((entry: any, index: number) => (
          <div key={index} className="flex items-center gap-2 py-0.5">
            <span className="w-2.5 h-2.5 rounded-sm" style={{ backgroundColor: entry.color }}></span>
            <span className="text-slate-600 font-medium">{entry.name}: </span>
            <span className="font-bold text-slate-800 ml-auto pl-4">
              {typeof entry.value === 'number' && entry.value > 1000 || entry.name.includes('Doanh thu') || entry.name.includes('Giá trị')
                ? formatCurrencyTy(entry.value) 
                : formatNumber(entry.value)}
            </span>
          </div>
        ))}
      </div>
    );
  }
  return null;
};

// --- Funnel Chart ---
export const LeadFunnelChart = ({ data }: { data: FunnelStage[] }) => {
  return (
    <ResponsiveContainer width="100%" height={320}>
      <FunnelChart>
        <RechartsTooltip content={<CustomTooltip />} cursor={{ fill: 'transparent' }} />
        <Funnel
          dataKey="count"
          data={data}
          isAnimationActive
        >
          <LabelList 
            position="right" 
            fill="#0f172a" 
            stroke="none" 
            dataKey="stage" 
            content={(props: any) => {
                const { x, y, width, value, index } = props;
                const item = data[index];
                const percentage = index === 0 ? 100 : Math.round((item.count / data[0].count) * 100);
                const prevCount = index > 0 ? data[index-1].count : 0;
                const dropOff = index > 0 ? Math.round(((prevCount - item.count) / prevCount) * 100) : 0;

                return (
                    <text x={x + width + 15} y={y + 22} fill="#64748b" className="text-xs">
                        <tspan x={x + width + 15} dy="0" className="text-slate-800 font-bold text-sm" fill="#1e293b">{value}</tspan>
                        <tspan x={x + width + 15} dy="1.4em" className="text-slate-500 font-medium">
                           {formatNumber(item.count)} <tspan fill="#94a3b8" fontSize="11px">({percentage}% giữ lại)</tspan>
                        </tspan>
                    </text>
                )
            }}
          />
        </Funnel>
      </FunnelChart>
    </ResponsiveContainer>
  );
};

