import React, { useEffect, useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { 
  Card, CardContent, CardHeader, CardTitle, 
  Button, Select, Tabs, Badge, Skeleton, TooltipWrapper 
} from './components/ui';
import { 
  LeadFunnelChart, SourcePieChart, RevenueLineChart, InventoryBarChart 
} from './components/charts';
import { getDashboardData } from './data';
import { DashboardData, FilterState } from './types';
import { formatNumber, formatCurrencyTy, cn } from './utils';
import { RotateCcw, Calendar, Download, Share2, MoreHorizontal } from 'lucide-react';

const PERIOD_OPTIONS = [
  { label: '7 Ngày Gần Nhất', value: '7days' },
  { label: '30 Ngày Qua', value: '30days' },
  { label: 'Tháng Này', value: 'month' },
  { label: 'Quý Này', value: 'quarter' },
];

const STATUS_OPTIONS = [
  { label: 'Tất cả Sản Phẩm', value: 'all' },
  { label: 'Đã Bán', value: 'sold' },
  { label: 'Cho Thuê', value: 'rent' },
];

export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<DashboardData | null>(null);
  const [filters, setFilters] = useState<FilterState>({ period: '7days', status: 'all' });
  const [activeTab, setActiveTab] = useState('overview');
  const [highlightedSource, setHighlightedSource] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const result = await getDashboardData(filters);
      setData(result);
      const now = new Date();
      setLastUpdated(now.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}));
    } catch (error) {
      console.error("Failed to load data", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [filters]);

  const handleReset = () => {
    setFilters({ period: '7days', status: 'all' });
    setHighlightedSource(null);
  };

  // Helper to render trend badge
  const renderTrend = (type: 'positive' | 'negative' | 'neutral', value?: string) => {
    if (!value) return null;
    if (type === 'positive') return <Badge variant="success" className="ml-auto">{value}</Badge>;
    if (type === 'negative') return <Badge variant="danger" className="ml-auto">{value}</Badge>;
    return <Badge variant="neutral" className="ml-auto">{value}</Badge>;
  };

  return (
    <div className="min-h-screen bg-slate-50/80 font-sans text-slate-900 flex selection:bg-indigo-100 selection:text-indigo-900">
      {/* Sidebar */}
      <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

      {/* Main Content */}
      <main 
        className={cn(
          "flex-1 transition-all duration-300 min-h-screen flex flex-col",
          sidebarOpen ? "ml-68" : "ml-18"
        )}
      >
        <div className="p-6 lg:p-10 space-y-8 max-w-[1920px] mx-auto w-full">

          {/* Header & Controls */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div>
              <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Tổng Quan Hoạt Động</h1>
              <div className="flex items-center gap-2 mt-2">
                 <span className="text-slate-500 text-sm">Cập nhật lần cuối: <span className="font-medium text-slate-700">{lastUpdated}</span></span>
                 <span className="text-slate-300">•</span>
                 <span className="text-slate-500 text-sm">Kỳ dữ liệu: <span className="font-medium text-slate-700">{filters.period === '7days' ? '7 ngày' : '30 ngày'}</span></span>
              </div>
            </div>

            <div className="flex items-center gap-3">
               <Button variant="outline" size="sm" className="hidden sm:flex gap-2 text-slate-600">
                  <Share2 size={16} /> Chia sẻ
               </Button>
               <Button variant="primary" size="sm" className="gap-2 shadow-lg shadow-indigo-200">
                  <Download size={16} /> Xuất Báo Cáo
               </Button>
            </div>
          </div>

          {/* Filter Bar */}
          <div className="sticky top-0 z-20 bg-slate-50/80 backdrop-blur-md py-4 -my-4 border-b border-slate-200/60 flex flex-col xl:flex-row items-start xl:items-center justify-between gap-4">
            <div className="flex items-center gap-4 w-full xl:w-auto overflow-x-auto pb-1 xl:pb-0 no-scrollbar">
              <Tabs 
                activeTab={activeTab} 
                onChange={setActiveTab} 
                tabs={[
                  { id: 'overview', label: 'Kinh Doanh' }, 
                  { id: 'marketing', label: 'Marketing' },
                  { id: 'inventory', label: 'Kho Hàng' }
                ]} 
              />
              <div className="h-8 w-px bg-slate-200 mx-2 hidden sm:block"></div>
              <div className="flex items-center gap-2">
                  <Calendar size={18} className="text-slate-400" />
                  <Select 
                    value={filters.period} 
                    onChange={(val) => setFilters(prev => ({ ...prev, period: val }))} 
                    options={PERIOD_OPTIONS} 
                  />
              </div>
            </div>

            <div className="flex flex-wrap items-center gap-3 w-full xl:w-auto justify-end">
              <Select 
                value={filters.status} 
                onChange={(val) => setFilters(prev => ({ ...prev, status: val }))} 
                options={STATUS_OPTIONS} 
              />
              <Button variant="ghost" size="icon" onClick={handleReset} title="Reset Bộ Lọc" className="text-slate-400 hover:text-slate-600">
                <RotateCcw size={18} />
              </Button>
            </div>
          </div>

          {/* KPI Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-5">
            {loading ? Array(6).fill(0).map((_, i) => (
              <Card key={i} className="h-32 border-none shadow-none bg-slate-200/50">
                <CardContent className="h-full flex flex-col justify-center gap-3 p-4">
                  <Skeleton className="h-4 w-24 bg-slate-300/50" />
                  <Skeleton className="h-8 w-16 bg-slate-300/50" />
                </CardContent>
              </Card>
            )) : data?.kpi.map((item, idx) => (
              <TooltipWrapper key={item.id} content={item.tooltip}>
                <Card className={cn(
                    "hover:-translate-y-1 transition-transform duration-300 relative overflow-hidden group border-l-4",
                    item.changeType === 'negative' ? 'border-l-rose-500' : 'border-l-indigo-500'
                )}>
                  <CardContent className="p-5 flex flex-col justify-between h-full relative z-10">
                    <div className="flex justify-between items-start">
                        <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">{item.label}</span>
                        {/* <span className={cn("p-1.5 rounded-md bg-slate-50 text-slate-400 group-hover:text-indigo-600 group-hover:bg-indigo-50 transition-colors")}>
                             <MoreHorizontal size={14} />
                        </span> */}
                    </div>
                    <div className="mt-4">
                      <div className="flex items-baseline gap-1.5">
                        <span className="text-3xl font-bold text-slate-800 tracking-tight">
                          {item.unit === 'tỷ' ? formatCurrencyTy(item.value).replace(' tỷ', '') : formatNumber(item.value)}
                        </span>
                        {item.unit && <span className="text-sm font-semibold text-slate-500 relative top-[-4px]">{item.unit}</span>}
                      </div>
                      <div className="mt-3 flex items-center text-xs font-medium">
                        {renderTrend(item.changeType, item.changeValue)}
                        <span className="text-slate-400 ml-2 font-normal">so với kỳ trước</span>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </TooltipWrapper>
            ))}
          </div>

          {/* Charts Row 1 */}
          <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 lg:gap-8">
            {/* Funnel */}
            <Card className="xl:col-span-2">
              <CardHeader>
                <CardTitle>Phễu Chuyển Đổi (Sales Funnel)</CardTitle>
                <div className="flex gap-2">
                    <Badge variant="neutral">Real-time</Badge>
                </div>
              </CardHeader>
              <CardContent>
                {loading ? <Skeleton className="h-[320px] w-full" /> : (
                  <LeadFunnelChart data={data?.funnel || []} />
                )}
              </CardContent>
            </Card>

            {/* Source Pie */}
            <Card className="xl:col-span-1 flex flex-col">
              <CardHeader>
                <CardTitle>Nguồn Khách Hàng</CardTitle>
                <Button variant="ghost" size="icon" className="h-8 w-8 text-slate-400"><MoreHorizontal size={16}/></Button>
              </CardHeader>
              <CardContent className="flex-1 flex flex-col p-0">
                <div className="flex-1 min-h-[240px] mt-4 px-4">
                   {loading ? <Skeleton className="h-full w-full" /> : (
                     <SourcePieChart 
                        data={data?.leadSources || []} 
                        onSelect={(name) => setHighlightedSource(name === highlightedSource ? null : name)} 
                     />
                   )}
                </div>

                {!loading && data && (
                  <div className="mt-2 border-t border-slate-100 max-h-[200px] overflow-y-auto custom-scrollbar">
                    <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 text-slate-500 font-semibold sticky top-0 z-10">
                        <tr>
                          <th className="px-5 py-3 text-xs uppercase tracking-wider">Kênh</th>
                          <th className="px-5 py-3 text-right text-xs uppercase tracking-wider">Lead</th>
                          <th className="px-5 py-3 text-right text-xs uppercase tracking-wider">Deal</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                        {data.leadSources.map((source) => (
                          <tr 
                            key={source.name} 
                            className={cn(
                                "transition-all cursor-pointer group",
                                highlightedSource && highlightedSource !== source.name ? "opacity-30 blur-[1px]" : "opacity-100",
                                highlightedSource === source.name ? "bg-indigo-50/60" : "hover:bg-slate-50"
                            )}
                            onClick={() => setHighlightedSource(highlightedSource === source.name ? null : source.name)}
                          >
                            <td className="px-5 py-3 font-medium flex items-center gap-2.5 text-slate-700">
                                <span className="w-2.5 h-2.5 rounded-full ring-2 ring-white shadow-sm" style={{ backgroundColor: source.color }} />
                                {source.name}
                            </td>
                            <td className="px-5 py-3 text-right text-slate-600 font-medium">{source.value}</td>
                            <td className="px-5 py-3 text-right text-slate-900 font-bold">{source.deals}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Charts Row 2 */}
          <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 lg:gap-8 pb-10">
             {/* Revenue Area Chart */}
             <Card>
              <CardHeader>
                <CardTitle>Dòng Tiền & Doanh Thu (Tỷ VNĐ)</CardTitle>
