// --- Funnel Chart ---
export const LeadFunnelChart = ({ data }: { data: FunnelStage[] }) => {
  return (
    <ResponsiveContainer width="100%" height={380}>
      <FunnelChart>
        <RechartsTooltip content={<CustomTooltip />} cursor={{ fill: 'transparent' }} />
        <Funnel
          dataKey="count"
          nameKey="stage"
          data={data}
          isAnimationActive
          x="20%" 
          width="60%"
        >
          {/* Inner Percentage Label */}
          <LabelList
            position="center"
            fill="#fff"
            stroke="none"
            dataKey="count"
            content={(props: any) => {
                const { x, y, width, height, value } = props;
                if (height < 20) return null;
                const firstVal = data[0].count;
                // Calculate percentage relative to top of funnel
                const percent = Math.round((value / firstVal) * 100);
                // For top one, maybe just show value or 100%? Let's show %

                return (
                     <text x={x + width / 2} y={y + height / 2} fill="#fff" textAnchor="middle" dominantBaseline="middle" className="text-xs font-bold drop-shadow-md pointer-events-none">
                        {percent}%
                     </text>
                );
            }}
          />

          {/* Alternating Side Labels */}
          <LabelList
            position="right"
            stroke="none"
            dataKey="stage"
            content={(props: any) => {
                const { x, y, width, height, value, index } = props;
                const item = data[index];

                // Render Label on Right for Even indices (0, 2, 4...)
                if (index % 2 === 0) {
                    return (
                        <g>
                            <line x1={x + width} y1={y + height / 2} x2={x + width + 15} y2={y + height / 2} stroke="#cbd5e1" strokeDasharray="2 2" />
                            <circle cx={x + width + 15} cy={y + height / 2} r={3} fill="#fff" stroke="#94a3b8" strokeWidth={1.5} />
                            <text x={x + width + 25} y={y + height / 2} dominantBaseline="middle" className="text-xs">
                                <tspan className="font-bold fill-slate-800 uppercase text-[10px] tracking-wide">{value}</tspan>
                                <tspan x={x + width + 25} dy="1.4em" className="fill-slate-500 font-medium">{formatNumber(item.count)}</tspan>
                            </text>
                        </g>
                    )
                }

                // Render Label on Left for Odd indices (1, 3, 5...)
                if (index % 2 !== 0) {
                    return (
                        <g>
                             <line x1={x} y1={y + height / 2} x2={x - 15} y2={y + height / 2} stroke="#cbd5e1" strokeDasharray="2 2" />
                             <circle cx={x - 15} cy={y + height / 2} r={3} fill="#fff" stroke="#94a3b8" strokeWidth={1.5} />
                             <text x={x - 25} y={y + height / 2} textAnchor="end" dominantBaseline="middle" className="text-xs">
                                <tspan className="font-bold fill-slate-800 uppercase text-[10px] tracking-wide">{value}</tspan>
                                <tspan x={x - 25} dy="1.4em" className="fill-slate-500 font-medium">{formatNumber(item.count)}</tspan>
                            </text>
                        </g>
                    )
                }
                return null;
            }}
          />
        </Funnel>
      </FunnelChart>
    </ResponsiveContainer>
  );
};

