import React, { useEffect, useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { 
  Card, CardContent, CardHeader, CardTitle, 
  Button, Select, Tabs, Badge, Skeleton, TooltipWrapper 
} from './components/ui';
import { 
  LeadFunnelChart, SourcePieChart, RevenueLineChart, InventoryBarChart 
} from './components/charts';
import { getDashboardData } from './data';
import { DashboardData, FilterState, KPIItem } from './types';
import { formatNumber, formatCurrencyTy, cn } from './utils';
import { 
  RotateCcw, Calendar, Download, Share2, MoreHorizontal,
  Users, Briefcase, CheckCircle2, Banknote, Building, Percent,
  TrendingUp, TrendingDown, Minus
} from 'lucide-react';

const PERIOD_OPTIONS = [
  { label: '7 Ngày Gần Nhất', value: '7days' },
  { label: '30 Ngày Qua', value: '30days' },
  { label: 'Tháng Này', value: 'month' },
  { label: 'Quý Này', value: 'quarter' },
];

const STATUS_OPTIONS = [
  { label: 'Tất cả Sản Phẩm', value: 'all' },
  { label: 'Đã Bán', value: 'sold' },
  { label: 'Cho Thuê', value: 'rent' },
];

// Map KPI IDs to Icons and Colors
const getKPIConfig = (id: string) => {
  switch(id) {
    case '1': return { icon: Users, color: 'text-blue-600', bg: 'bg-blue-50' }; // Lead
    case '2': return { icon: Briefcase, color: 'text-violet-600', bg: 'bg-violet-50' }; // Deal
    case '3': return { icon: CheckCircle2, color: 'text-emerald-600', bg: 'bg-emerald-50' }; // Giao Dịch
    case '4': return { icon: Banknote, color: 'text-amber-600', bg: 'bg-amber-50' }; // Doanh Số
    case '5': return { icon: Building, color: 'text-indigo-600', bg: 'bg-indigo-50' }; // Giỏ Hàng
    case '6': return { icon: Percent, color: 'text-rose-600', bg: 'bg-rose-50' }; // Tỷ Lệ
    default: return { icon: Users, color: 'text-slate-600', bg: 'bg-slate-50' };
  }
}

export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<DashboardData | null>(null);
  const [filters, setFilters] = useState<FilterState>({ period: '7days', status: 'all' });
  const [activeTab, setActiveTab] = useState('overview');
  const [highlightedSource, setHighlightedSource] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const result = await getDashboardData(filters);
      setData(result);
      const now = new Date();
      setLastUpdated(now.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}));
    } catch (error) {
      console.error("Failed to load data", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [filters]);

  const handleReset = () => {
    setFilters({ period: '7days', status: 'all' });
    setHighlightedSource(null);
  };

  // Helper to render trend badge
  const renderTrend = (type: 'positive' | 'negative' | 'neutral', value?: string) => {
    if (!value) return null;

    let Icon = Minus;
    let colorClass = "text-slate-500 bg-slate-100";

    if (type === 'positive') {
      Icon = TrendingUp;
      colorClass = "text-emerald-700 bg-emerald-50 border-emerald-100";
    } else if (type === 'negative') {
      Icon = TrendingDown;
      colorClass = "text-rose-700 bg-rose-50 border-rose-100";
    }

    return (
      <div className={cn("flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-bold border", colorClass)}>
        <Icon size={12} />
        {value}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans text-slate-900 flex selection:bg-indigo-100 selection:text-indigo-900">
      {/* Sidebar */}
      <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

      {/* Main Content */}
      <main 
        className={cn(
          "flex-1 transition-all duration-300 ease-in-out min-h-screen flex flex-col",
          sidebarOpen ? "ml-[260px]" : "ml-[80px]"
        )}
      >
        <div className="p-6 lg:p-8 space-y-8 max-w-[1920px] mx-auto w-full">

          {/* Header & Controls */}
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-2">
            <div>
              <h1 className="text-2xl md:text-3xl font-extrabold text-slate-800 tracking-tight">Tổng Quan Hoạt Động</h1>
              <div className="flex items-center gap-2 mt-2">
                 <Badge variant="indigo" className="font-normal text-[11px] py-0.5">Real-time Data</Badge>
                 <span className="text-slate-400 text-sm">•</span>
                 <span className="text-slate-500 text-sm">Cập nhật: {lastUpdated}</span>
              </div>
            </div>

            <div className="flex items-center gap-3">
               <Button variant="outline" className="hidden sm:flex gap-2 text-slate-600 border-slate-200 shadow-sm bg-white">
                  <Share2 size={16} /> Chia sẻ
               </Button>
               <Button variant="primary" className="gap-2 shadow-lg shadow-indigo-200 hover:shadow-indigo-300">
                  <Download size={16} /> Xuất Báo Cáo
               </Button>
            </div>
          </div>

          {/* Filter Bar */}
          <div className="sticky top-0 z-20 bg-[#F8FAFC]/90 backdrop-blur-md py-4 -my-4 border-b border-slate-200/60 flex flex-col xl:flex-row items-start xl:items-center justify-between gap-4 transition-all">
            <div className="flex items-center gap-4 w-full xl:w-auto overflow-x-auto pb-1 xl:pb-0 no-scrollbar">
              <Tabs 
                activeTab={activeTab} 
                onChange={setActiveTab} 
                tabs={[
                  { id: 'overview', label: 'Kinh Doanh' }, 
                  { id: 'marketing', label: 'Marketing' },
                  { id: 'inventory', label: 'Kho Hàng' }
                ]} 
              />
              <div className="h-6 w-px bg-slate-300 mx-2 hidden sm:block"></div>
              <div className="flex items-center gap-2">
                  <Calendar size={18} className="text-slate-400" />
                  <Select 
                    value={filters.period} 
                    onChange={(val) => setFilters(prev => ({ ...prev, period: val }))} 
                    options={PERIOD_OPTIONS} 
                  />
              </div>
            </div>

            <div className="flex flex-wrap items-center gap-3 w-full xl:w-auto justify-end">
              <Select 
                value={filters.status} 
                onChange={(val) => setFilters(prev => ({ ...prev, status: val }))} 
                options={STATUS_OPTIONS} 
              />
              <Button variant="ghost" size="icon" onClick={handleReset} title="Reset Bộ Lọc" className="text-slate-400 hover:text-indigo-600 bg-white border border-slate-200 shadow-sm">
                <RotateCcw size={16} />
              </Button>
            </div>
          </div>

          {/* KPI Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4 lg:gap-5">
            {loading ? Array(6).fill(0).map((_, i) => (
              <Card key={i} className="h-36 border-transparent bg-white">
                <CardContent className="h-full flex flex-col gap-3 p-5">
                  <div className="flex justify-between">
                     <Skeleton className="h-10 w-10 rounded-full" />
                  </div>
                  <Skeleton className="h-8 w-24 mt-auto" />
                  <Skeleton className="h-3 w-16" />
                </CardContent>
              </Card>
            )) : data?.kpi.map((item, idx) => {
              const { icon: Icon, color, bg } = getKPIConfig(item.id);
              return (
              <TooltipWrapper key={item.id} content={item.tooltip}>
                <Card className="hover:-translate-y-1 h-full">
                  <CardContent className="p-5 flex flex-col justify-between h-full">
                    <div className="flex justify-between items-start mb-3">
                        <div className={cn("p-2.5 rounded-xl", bg, color)}>
                            <Icon size={20} />
                        </div>
                        {renderTrend(item.changeType, item.changeValue)}
                    </div>

                    <div className="space-y-1">
                      <h4 className="text-slate-500 text-xs font-semibold uppercase tracking-wide truncate" title={item.label}>
                        {item.label}
