  { name: 'Sự Kiện / Event', value: 50, deals: 1, color: '#f59e0b' }, // Amber
  { name: 'Zalo / Direct', value: 40, deals: 1, color: '#8b5cf6' }, // Purple
];

const revenueBase: RevenueData[] = [
  { name: 'T2', completed: 8.5, pending: 12, cancelled: 0 },
  { name: 'T3', completed: 12.0, pending: 15, cancelled: 2 },
  { name: 'T4', completed: 25.5, pending: 20, cancelled: 1.5 },
  { name: 'T5', completed: 18.2, pending: 28, cancelled: 5 },
  { name: 'T6', completed: 32.5, pending: 22, cancelled: 3 },
  { name: 'T7', completed: 15.8, pending: 18, cancelled: 0 },
  { name: 'CN', completed: 0, pending: 5, cancelled: 0 },
];

const inventoryBase: InventoryCategory[] = [
  { category: 'Căn Hộ CC', sell: 1250, rent: 450 },
  { category: 'Nhà Phố', sell: 1800, rent: 200 },
  { category: 'Biệt Thự', sell: 1500, rent: 150 },
  { category: 'Đất Nền', sell: 400, rent: 0 },
  { category: 'Shophouse', sell: 350, rent: 180 },
  { category: 'Khác', sell: 120, rent: 50 },
];

export const getDashboardData = (filter: FilterState): Promise<DashboardData> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      let kpi = [...kpiBase];
      let revenue = [...revenueBase];
      let funnel = [...funnelBase];

      if (filter.period === '30days') {
        kpi = kpi.map(item => ({ 
            ...item, 
            value: item.id === '5' || item.id === '6' ? item.value : Math.round(item.value * 2.5) 
        }));
        funnel = funnel.map(item => ({ ...item, count: Math.round(item.count * 2.5) }));
        revenue = revenue.map(item => ({ 
            ...item, 
            completed: item.completed * 1.5, 
            pending: item.pending * 1.5 
        }));
      }

      if (filter.status === 'sold') {
         kpi[1].value = 20; // Fewer pending
      }

      resolve({
        kpi,
        funnel,
        leadSources: sourceBase,
        revenue,
        inventory: inventoryBase
      });
    }, 800);
  });
};

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, Skeleton, Button, TooltipWrapper } from './ui';
import { FunnelStage, FunnelStageKey } from '../types';
import { formatNumber, cn } from '../utils';
import { RotateCcw, Filter } from 'lucide-react';

interface FunnelCardProps {
  data: FunnelStage[];
  selectedStage?: string;
  onSelectStage: (key: FunnelStageKey) => void;
  isLoading?: boolean;
}

// --- Geometry Constants ---
const VIEWBOX_WIDTH = 800;
const VIEWBOX_HEIGHT = 500;
const CENTER_X = VIEWBOX_WIDTH / 2;
const FUNNEL_TOP_Y = 50;
const FUNNEL_HEIGHT = 400; // Total height of the funnel stack
const MAX_FUNNEL_WIDTH = 400; // Width at top
const MIN_FUNNEL_WIDTH = 120; // Width at bottom
const GAP = 4; // Gap between stages

export const FunnelCard: React.FC<FunnelCardProps> = ({ 
  data, 
  selectedStage, 
  onSelectStage, 
  isLoading 
}) => {
  const [hoveredStage, setHoveredStage] = useState<string | null>(null);

  if (isLoading) {
    return (
      <Card className="h-full min-h-[500px]">
        <CardHeader>
          <Skeleton className="h-8 w-64" />
        </CardHeader>
        <CardContent className="flex flex-col items-center justify-center space-y-4">
          <Skeleton className="h-[350px] w-[60%] rounded-b-3xl" />
          <div className="w-full grid grid-cols-2 gap-8 px-12">
             <Skeleton className="h-4 w-full" />
             <Skeleton className="h-4 w-full" />
             <Skeleton className="h-4 w-full" />
             <Skeleton className="h-4 w-full" />
          </div>
        </CardContent>
      </Card>
    );
  }

  if (!data || data.length === 0) {
    return (
      <Card className="h-full min-h-[500px] flex flex-col items-center justify-center p-8 text-center">
        <div className="bg-slate-50 p-4 rounded-full mb-4">
          <Filter className="text-slate-400" size={32} />
        </div>
        <h3 className="text-slate-800 font-semibold mb-2">Chưa có dữ liệu phễu</h3>
        <p className="text-slate-500 text-sm mb-6 max-w-xs">Không tìm thấy dữ liệu trong khoảng thời gian này.</p>
        <Button variant="outline" onClick={() => window.location.reload()}>
          <RotateCcw size={14} className="mr-2" /> Tải lại trang
        </Button>
      </Card>
    );
  }

  const stageHeight = (FUNNEL_HEIGHT - (data.length - 1) * GAP) / data.length;

  // Helper to calculate trapezoid points
  const getStageGeometry = (index: number) => {
    const yTop = FUNNEL_TOP_Y + index * (stageHeight + GAP);
    const yBottom = yTop + stageHeight;

    // Linear interpolation for width
    const tTop = index / data.length;
    const tBottom = (index + 1) / data.length;

    const wTop = MAX_FUNNEL_WIDTH - tTop * (MAX_FUNNEL_WIDTH - MIN_FUNNEL_WIDTH);
    const wBottom = MAX_FUNNEL_WIDTH - tBottom * (MAX_FUNNEL_WIDTH - MIN_FUNNEL_WIDTH);

    const xTopLeft = CENTER_X - wTop / 2;
    const xTopRight = CENTER_X + wTop / 2;
    const xBottomLeft = CENTER_X - wBottom / 2;
    const xBottomRight = CENTER_X + wBottom / 2;

    const path = `M ${xTopLeft},${yTop} L ${xTopRight},${yTop} L ${xBottomRight},${yBottom} L ${xBottomLeft},${yBottom} Z`;

    // For Leader Lines
    const yCenter = yTop + stageHeight / 2;
    const xLeftEdge = CENTER_X - (wTop + wBottom) / 4; // Approx center edge x
    const xRightEdge = CENTER_X + (wTop + wBottom) / 4;

    return { path, yCenter, xLeftEdge, xRightEdge, xTopLeft, xTopRight, wTop };
  };

  return (
    <Card className="h-full overflow-hidden bg-white">
      <CardHeader>
        <CardTitle>Tiến Trình Lead → Deal → Giao Dịch</CardTitle>
      </CardHeader>
      <CardContent className="p-0 relative w-full aspect-[8/5] min-h-[450px]">
        <svg 
          viewBox={`0 0 ${VIEWBOX_WIDTH} ${VIEWBOX_HEIGHT}`} 
          className="w-full h-full select-none"
          preserveAspectRatio="xMidYMid meet"
        >
          <defs>
            <filter id="shadow" x="-20%" y="-20%" width="140%" height="140%">
              <feDropShadow dx="0" dy="4" stdDeviation="4" floodColor="#000" floodOpacity="0.15" />
            </filter>
          </defs>

          {data.map((stage, index) => {
            const geo = getStageGeometry(index);
            const isHovered = hoveredStage === stage.key;
            const isSelected = selectedStage === stage.key;
            const isDimmed = selectedStage && !isSelected;

            // Interaction States
            const opacity = isDimmed ? 0.4 : (isHovered ? 1 : 0.9);
            const stroke = isSelected || isHovered ? "white" : "none";
            const strokeWidth = isSelected ? 3 : (isHovered ? 2 : 0);

            // Leader Line Coords
            const labelX = stage.side === 'left' ? 140 : VIEWBOX_WIDTH - 140;
            const lineStartX = stage.side === 'left' ? geo.xLeftEdge : geo.xRightEdge;
            const lineEndX = stage.side === 'left' ? labelX + 20 : labelX - 20;

            return (
              <g 
                key={stage.key}
                onClick={() => onSelectStage(stage.key)}
                onMouseEnter={() => setHoveredStage(stage.key)}
                onMouseLeave={() => setHoveredStage(null)}
                className="cursor-pointer transition-all duration-300"
                style={{ opacity: isDimmed && !isHovered ? 0.5 : 1 }}
              >
                {/* 1. Funnel Shape */}
                <path
                  d={geo.path}
                  fill={stage.color}
                  stroke={stroke}
                  strokeWidth={strokeWidth}
                  filter={isSelected ? "url(#shadow)" : undefined}
                  className="transition-all duration-300 ease-in-out"
                />

                {/* 3D Top Cap (Only for first stage) */}
                {index === 0 && (
                  <ellipse 
                    cx={CENTER_X} 
                    cy={FUNNEL_TOP_Y} 
                    rx={geo.wTop / 2} 
                    ry={10} 
                    fill="none" 
                    stroke="rgba(255,255,255,0.6)" 
                    strokeWidth="1.5"
                  />
                )}

                {/* 2. Percentage Text (Centered) */}
                <text
                  x={CENTER_X}
                  y={geo.yCenter}
                  dominantBaseline="middle"
                  textAnchor="middle"
                  fill="white"
                  className={cn(
                    "font-bold text-sm tracking-wide drop-shadow-md pointer-events-none transition-transform duration-300",
                    (isHovered || isSelected) ? "scale-125" : "scale-100"
                  )}
                >
                  {formatNumber(stage.percent)}%
                </text>

                {/* 3. Leader Line */}
                <line 
                  x1={lineStartX} 
                  y1={geo.yCenter} 
                  x2={lineEndX} 
                  y2={geo.yCenter} 
                  stroke={isHovered || isSelected ? stage.color : "#cbd5e1"} 
                  strokeWidth="1.5" 
                  strokeDasharray="4 3"
                  className="transition-colors duration-300"
                />

                {/* 4. Label Block */}
                <foreignObject 
                    x={stage.side === 'left' ? 0 : VIEWBOX_WIDTH - 280} 
                    y={geo.yCenter - 25} 
                    width={280} 
                    height={50}
                >
                    <div className={cn(
                        "w-full h-full flex items-center px-6 transition-transform duration-200",
                        stage.side === 'left' ? "justify-end text-right" : "justify-start text-left",
                        isHovered ? "scale-105" : "scale-100"
                    )}>
                         {/* Left Side Layout: Text | Dot */}
                         {stage.side === 'left' && (
                            <>
                                <div className="mr-3">
                                    <div className={cn("text-[11px] font-bold uppercase tracking-wider mb-0.5", isSelected || isHovered ? "text-slate-900" : "text-slate-500")}>
                                        {stage.label}
                                    </div>
                                    <div className={cn("text-sm font-bold", isSelected || isHovered ? "text-indigo-600" : "text-slate-700")}>
                                        {formatNumber(stage.count)}
                                    </div>
                                </div>
                                <div className={cn("w-3 h-3 rounded-full border-[2.5px] bg-white z-10", isSelected || isHovered ? "border-indigo-500 scale-125" : "border-slate-300")} />
                            </>
                         )}

                         {/* Right Side Layout: Dot | Text */}
                         {stage.side === 'right' && (
                            <>
                                <div className={cn("w-3 h-3 rounded-full border-[2.5px] bg-white z-10", isSelected || isHovered ? "border-indigo-500 scale-125" : "border-slate-300")} />
                                <div className="ml-3">
                                    <div className={cn("text-[11px] font-bold uppercase tracking-wider mb-0.5", isSelected || isHovered ? "text-slate-900" : "text-slate-500")}>
                                        {stage.label}
                                    </div>
                                    <div className={cn("text-sm font-bold", isSelected || isHovered ? "text-indigo-600" : "text-slate-700")}>
                                        {formatNumber(stage.count)}
                                    </div>
                                </div>
                            </>
                         )}
                    </div>
                </foreignObject>
              </g>
            );
          })}
        </svg>
      </CardContent>
    </Card>
  );
};

