  { label: 'Đã Bán', value: 'sold' },
  { label: 'Cho Thuê', value: 'rent' },
];

// Map KPI IDs to Icons and Colors
const getKPIConfig = (id: string) => {
  switch(id) {
    case '1': return { icon: Users, color: 'text-blue-600', bg: 'bg-blue-50' }; // Lead
    case '2': return { icon: Briefcase, color: 'text-violet-600', bg: 'bg-violet-50' }; // Deal
    case '3': return { icon: CheckCircle2, color: 'text-emerald-600', bg: 'bg-emerald-50' }; // Giao Dịch
    case '4': return { icon: Banknote, color: 'text-amber-600', bg: 'bg-amber-50' }; // Doanh Số
    case '5': return { icon: Building, color: 'text-indigo-600', bg: 'bg-indigo-50' }; // Giỏ Hàng
    case '6': return { icon: Percent, color: 'text-rose-600', bg: 'bg-rose-50' }; // Tỷ Lệ
    default: return { icon: Users, color: 'text-slate-600', bg: 'bg-slate-50' };
  }
}

export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loading, setLoading] = useState(true);
