  const [selectedFunnelStage, setSelectedFunnelStage] = useState<FunnelStageKey | undefined>(undefined);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const result = await getDashboardData(filters);
      setData(result);
      const now = new Date();
      setLastUpdated(now.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}));
    } catch (error) {
      console.error("Failed to load data", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [filters]);

  const handleReset = () => {
    setFilters({ period: '7days', status: 'all' });
    setHighlightedSource(null);
    setSelectedFunnelStage(undefined);
