    if (type === 'positive') {
      Icon = TrendingUp;
      colorClass = "text-emerald-700 bg-emerald-50 border-emerald-100";
    } else if (type === 'negative') {
      Icon = TrendingDown;
      colorClass = "text-rose-700 bg-rose-50 border-rose-100";
    }

    return (
      <div className={cn("flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-bold border", colorClass)}>
