                <div className="overflow-y-auto custom-scrollbar flex-1 max-h-[460px]">
                   <table className="w-full text-sm text-left">
                       <thead className="bg-slate-50 text-slate-500 font-semibold sticky top-0 z-10">
                           <tr>
                               <th className="px-4 py-3 text-[11px] uppercase tracking-wider">Loại Hình</th>
