                               )}
                           </tr>
                       </thead>
                       <tbody className="divide-y divide-slate-100">
                           {isLoading 
                             ? Array(6).fill(0).map((_, i) => (
                                 <tr key={i}><td colSpan={3} className="p-4"><Skeleton className="h-4 w-full" /></td></tr>
                               ))
                             : data.map((item, idx) => (
                               <tr key={idx} className="hover:bg-slate-50/80 transition-colors group">
                                   <td className="px-4 py-3 font-medium text-slate-700">{item.type}</td>
                                   {(filters.itemType === 'tat_ca' || filters.itemType === 'ban') && (
                                       <td className="px-4 py-3 text-right font-semibold text-slate-600 group-hover:text-amber-600">
                                           {getFormat(getValue(item, 'sell', filters.metricMode), filters.metricMode)}
