    { label: 'Tháng Này', value: 'thang_nay' },
    { label: 'Quý Này', value: 'quy_nay' },
    { label: 'Tùy Chỉnh...', value: 'tuy_chinh' },
];

const INVENTORY_SCOPE_OPTIONS = [
    { label: 'Tất cả Hàng Hóa', value: 'tat_ca_hang_hoa' },
    { label: 'Hàng Bán', value: 'hang_ban' },
    { label: 'Hàng Thuê', value: 'hang_thue' },
    { label: 'Đã Chốt', value: 'da_chot' },
    { label: 'Đang Mở', value: 'dang_mo' },
];

const LEAD_STATUS_OPTIONS = [
    { label: 'Tất Cả', value: 'tat_ca' },
    { label: 'Lead Mới', value: 'lead_moi' },
    { label: 'Đang Chăm', value: 'dang_cham' },
    { label: 'Hẹn Xem Nhà', value: 'hen_xem_nha' },
    { label: 'Deal Mở', value: 'deal_mo' },
    { label: 'Đàm Phán', value: 'dam_phan' },
    { label: 'Đặt Cọc', value: 'dat_coc' },
    { label: 'GD Hoàn Tất', value: 'gd_hoan_tat' },
    { label: 'Thất Bại', value: 'that_bai' },
];

const DEFAULT_FILTERS: DetailedFilterState = {
    timeRange: "7_ngay_gan_nhat",
    inventoryScope: "tat_ca_hang_hoa",
    leadStatus: "tat_ca",
    itemType: "tat_ca",
    metricMode: "so_luong",
    propertyType: "tat_ca"
};

// Map KPI IDs to Icons
const getKPIConfig = (id: string) => {
  switch(id) {
    case '1': return { icon: Users, color: 'text-blue-600', bg: 'bg-blue-50' };
    case '2': return { icon: Briefcase, color: 'text-violet-600', bg: 'bg-violet-50' };
    case '3': return { icon: CheckCircle2, color: 'text-emerald-600', bg: 'bg-emerald-50' };
    case '4': return { icon: Banknote, color: 'text-amber-600', bg: 'bg-amber-50' };
    case '5': return { icon: Building, color: 'text-indigo-600', bg: 'bg-indigo-50' };
    case '6': return { icon: Percent, color: 'text-rose-600', bg: 'bg-rose-50' };
    default: return { icon: Users, color: 'text-slate-600', bg: 'bg-slate-50' };
  }
}

export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<DashboardData | null>(null);

  // Unified Filter State
  const [filters, setFilters] = useState<DetailedFilterState>(DEFAULT_FILTERS);

  const [activeTab, setActiveTab] = useState('overview');
  const [highlightedSource, setHighlightedSource] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const result = await getDashboardData(filters);
      setData(result);
      const now = new Date();
      setLastUpdated(now.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}));
    } catch (error) {
      console.error("Failed to load data", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [filters.timeRange, filters.inventoryScope, filters.propertyType, filters.leadStatus]); // Re-fetch on global changes

  const handleReset = () => {
    setFilters(DEFAULT_FILTERS);
    setHighlightedSource(null);
  };

  // Helper to render trend badge
  const renderTrend = (type: 'positive' | 'negative' | 'neutral', value?: string) => {
    if (!value) return null;
    let Icon = Minus;
    let colorClass = "text-slate-500 bg-slate-100";
    if (type === 'positive') { Icon = TrendingUp; colorClass = "text-emerald-700 bg-emerald-50 border-emerald-100"; } 
    else if (type === 'negative') { Icon = TrendingDown; colorClass = "text-rose-700 bg-rose-50 border-rose-100"; }
    return <div className={cn("flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-bold border", colorClass)}><Icon size={12} />{value}</div>;
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans text-slate-900 flex selection:bg-indigo-100 selection:text-indigo-900">
      <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

      <main className={cn("flex-1 transition-all duration-300 ease-in-out min-h-screen flex flex-col", sidebarOpen ? "ml-[260px]" : "ml-[80px]")}>
        <div className="p-6 lg:p-8 space-y-8 max-w-[1920px] mx-auto w-full">

          {/* Header */}
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-2">
            <div>
              <h1 className="text-2xl md:text-3xl font-extrabold text-slate-800 tracking-tight">Tổng Quan Hoạt Động</h1>
              <div className="flex items-center gap-2 mt-2">
                 <Badge variant="indigo" className="font-normal text-[11px] py-0.5">Real-time Data</Badge>
                 <span className="text-slate-400 text-sm">•</span>
                 <span className="text-slate-500 text-sm">Cập nhật: {lastUpdated}</span>
              </div>
            </div>
            <div className="flex items-center gap-3">
               <Button variant="outline" className="hidden sm:flex gap-2 text-slate-600 border-slate-200 shadow-sm bg-white"><Share2 size={16} /> Chia sẻ</Button>
               <Button variant="primary" className="gap-2 shadow-lg shadow-indigo-200 hover:shadow-indigo-300"><Download size={16} /> Xuất Báo Cáo</Button>
            </div>
          </div>

          {/* GLOBAL FILTER BAR */}
          <div className="sticky top-0 z-30 bg-[#F8FAFC]/95 backdrop-blur-md py-4 -my-4 border-b border-slate-200/60 flex flex-col xl:flex-row items-start xl:items-center justify-between gap-4 transition-all shadow-[0_4px_20px_-10px_rgba(0,0,0,0.05)] px-1 -mx-1">
            <div className="flex items-center gap-4 w-full xl:w-auto overflow-x-auto pb-1 xl:pb-0 no-scrollbar">
              <Tabs 
                activeTab={activeTab} 
                onChange={setActiveTab} 
                tabs={[
                  { id: 'overview', label: 'Tổng Quan' }, 
                  { id: 'inventory_detailed', label: 'Hàng Hóa Chi Tiết' },
                  { id: 'marketing', label: 'Marketing' }
                ]} 
              />
              <div className="h-6 w-px bg-slate-300 mx-2 hidden sm:block"></div>

              <div className="flex items-center gap-3">
                  <Select 
                    label="Thời gian"
                    value={filters.timeRange} 
                    onChange={(val) => setFilters(prev => ({ ...prev, timeRange: val as any }))} 
                    options={TIME_RANGE_OPTIONS}
                  />
                  <Select 
                    label="Phạm vi"
                    value={filters.inventoryScope}
                    onChange={(val) => setFilters(prev => ({ ...prev, inventoryScope: val as any }))}
                    options={INVENTORY_SCOPE_OPTIONS}
                  />
              </div>
            </div>

            <div className="flex flex-wrap items-center gap-3 w-full xl:w-auto justify-end">
              <Select 
                label="Trạng Thái Lead"
                value={filters.leadStatus} 
                onChange={(val) => setFilters(prev => ({ ...prev, leadStatus: val as any }))} 
                options={LEAD_STATUS_OPTIONS}
                className="min-w-[180px]"
              />
              <TooltipWrapper content="Khôi phục bộ lọc mặc định">
                <Button variant="ghost" size="icon" onClick={handleReset} className="mt-5 h-10 w-10 text-slate-400 hover:text-indigo-600 bg-white border border-slate-200 shadow-sm">
                    <RotateCcw size={16} />
                </Button>
              </TooltipWrapper>
            </div>
          </div>

          {/* KPI Grid (Always visible but data changes) */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4 lg:gap-5">
            {loading ? Array(6).fill(0).map((_, i) => (
              <Card key={i} className="h-36 border-transparent bg-white"><CardContent className="h-full p-5"><Skeleton className="h-full w-full" /></CardContent></Card>
            )) : data?.kpi.map((item) => {
              const { icon: Icon, color, bg } = getKPIConfig(item.id);
              return (
              <TooltipWrapper key={item.id} content={item.tooltip}>
                <Card className="hover:-translate-y-1 h-full">
                  <CardContent className="p-5 flex flex-col justify-between h-full">
                    <div className="flex justify-between items-start mb-3">
                        <div className={cn("p-2.5 rounded-xl", bg, color)}><Icon size={20} /></div>
                        {renderTrend(item.changeType, item.changeValue)}
                    </div>
                    <div>
                      <h4 className="text-slate-500 text-xs font-semibold uppercase tracking-wide truncate">{item.label}</h4>
                      <div className="flex items-baseline gap-1 mt-1">
                        <span className="text-2xl font-extrabold text-slate-800 tracking-tight">
                          {item.unit === 'tỷ' ? formatCurrencyTy(item.value).replace(' tỷ', '') : formatNumber(item.value)}
                        </span>
                        {item.unit && <span className="text-xs font-bold text-slate-500">{item.unit}</span>}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </TooltipWrapper>
            )})}
          </div>

          {/* --- VIEW SWITCHER --- */}
          {activeTab === 'overview' ? (
            <>
                {/* Overview: Funnel + Source */}
                <div className="grid grid-cols-1 xl:grid-cols-12 gap-6 lg:gap-8">
                    <div className="xl:col-span-8">
                        <FunnelCard 
                            data={data?.funnel || []} 
                            isLoading={loading}
                            selectedStage={filters.leadStatus !== 'tat_ca' && filters.leadStatus !== 'that_bai' ? filters.leadStatus as FunnelStageKey : undefined}
                            onSelectStage={(key) => setFilters(prev => ({ ...prev, leadStatus: prev.leadStatus === key ? 'tat_ca' : key }))}
                        />
                    </div>
                    <Card className="xl:col-span-4 flex flex-col">
                        <CardHeader>
                            <CardTitle>Nguồn Khách Hàng</CardTitle>
                            <Button variant="ghost" size="icon" className="h-8 w-8 text-slate-400 hover:bg-slate-100 rounded-full"><MoreHorizontal size={16}/></Button>
                        </CardHeader>
                        <CardContent className="flex-1 flex flex-col p-0 bg-slate-50/30">
                            <div className="flex-1 min-h-[240px] mt-6 px-4">
                            {loading ? <Skeleton className="h-full w-full" /> : (
                                <SourcePieChart 
                                    data={data?.leadSources || []} 
                                    onSelect={(name) => setHighlightedSource(name === highlightedSource ? null : name)} 
                                />
                            )}
                            </div>
                            {!loading && data && (
                            <div className="mt-4 border-t border-slate-100 max-h-[220px] overflow-y-auto custom-scrollbar bg-white rounded-b-2xl">
                                <table className="w-full text-sm text-left">
                                <thead className="bg-slate-50 text-slate-500 font-semibold sticky top-0 z-10">
                                    <tr>
                                    <th className="px-6 py-3 text-[10px] uppercase tracking-wider text-slate-400">Kênh</th>
                                    <th className="px-6 py-3 text-right text-[10px] uppercase tracking-wider text-slate-400">Lead</th>
                                    <th className="px-6 py-3 text-right text-[10px] uppercase tracking-wider text-slate-400">Deal</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {data.leadSources.map((source) => (
                                    <tr key={source.name} className={cn("transition-all cursor-pointer group hover:bg-slate-50", highlightedSource && highlightedSource !== source.name && "opacity-30 blur-[0.5px]", highlightedSource === source.name && "bg-indigo-50/70")} onClick={() => setHighlightedSource(highlightedSource === source.name ? null : source.name)}>
                                        <td className="px-6 py-3 font-medium flex items-center gap-2.5 text-slate-700">
                                            <span className="w-2.5 h-2.5 rounded-full ring-2 ring-white shadow-sm" style={{ backgroundColor: source.color }} />
                                            {source.name}
                                        </td>
                                        <td className="px-6 py-3 text-right text-slate-600 font-medium">{source.value}</td>
                                        <td className="px-6 py-3 text-right text-slate-900 font-bold">{source.deals}</td>
                                    </tr>
                                    ))}
                                </tbody>
                                </table>
                            </div>
                            )}
                        </CardContent>
                    </Card>
                </div>

                {/* Overview: Revenue + Simple Inventory */}
                <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 lg:gap-8 pb-12">
                    <Card>
                        <CardHeader>
                            <CardTitle><div className="p-2 bg-emerald-50 rounded-lg text-emerald-600 mr-1"><Banknote size={18}/></div>Dòng Tiền & Doanh Thu</CardTitle>
                        </CardHeader>
                        <CardContent className="bg-slate-50/30">
                            {loading ? <Skeleton className="h-[320px] w-full" /> : <RevenueLineChart data={data?.revenue || []} />}
                        </CardContent>
                    </Card>
                    <Card>
                        <CardHeader>
                            <CardTitle><div className="p-2 bg-amber-50 rounded-lg text-amber-600 mr-1"><Building size={18}/></div>Cơ Cấu Giỏ Hàng</CardTitle>
                            <Badge variant="warning">Tồn kho thấp</Badge>
                        </CardHeader>
                        <CardContent className="bg-slate-50/30">
                            {loading ? <Skeleton className="h-[320px] w-full" /> : <InventoryBarChart data={data?.inventory || []} />}
                        </CardContent>
                    </Card>
                </div>
            </>
          ) : activeTab === 'inventory_detailed' ? (
              <InventoryTab 
                 data={data?.inventoryDetailed || []} 
                 filters={filters} 
                 setFilters={setFilters} 
                 isLoading={loading} 
              />
          ) : (
            <div className="flex flex-col items-center justify-center min-h-[400px] text-slate-400">
                <Briefcase size={48} className="mb-4 opacity-50"/>
                <p>Chức năng Marketing đang được phát triển...</p>
            </div>
          )}

        </div>
      </main>
    </div>
  );
}

export interface KPIItem {
  id: string;
  label: string;
  value: number;
  unit?: string;
  changeValue?: string; // e.g., "+12%", "+5 Deals"
  changeType: 'positive' | 'negative' | 'neutral';
  tooltip: string;
}

export type FunnelStageKey =
  | "lead_moi"
  | "dang_cham"
  | "hen_xem_nha"
  | "deal_mo"
  | "dam_phan"
  | "dat_coc"
  | "gd_hoan_tat";

export interface FunnelStage {
  key: FunnelStageKey;
  label: string;
  count: number;
  percent: number;
  side: "left" | "right";
  color: string;
}

export interface LeadSource {
  name: string;
  value: number;
  deals: number;
  color: string;
}

export interface RevenueData {
  name: string; // Date or Period
  completed: number;
  pending: number;
  cancelled: number;
}

export interface InventoryCategory {
  category: string;
  sell: number; // Value in Ty
  rent: number; // Value in Ty
}

// --- NEW DETAILED INVENTORY TYPES ---

export type TimeRange = "7_ngay_gan_nhat" | "30_ngay_gan_nhat" | "thang_nay" | "quy_nay" | "tuy_chinh";
export type InventoryScope = "tat_ca_hang_hoa" | "hang_ban" | "hang_thue" | "da_chot" | "dang_mo";
export type LeadStatus = "tat_ca" | FunnelStageKey | "that_bai";
export type ItemType = "tat_ca" | "ban" | "cho_thue";
export type MetricMode = "so_luong" | "gia_tri" | "phi";
export type PropertyType = "tat_ca" | "chung_cu" | "lien_ke" | "biet_thu" | "nha_rieng" | "dat_nen" | "shophouse_kiosk" | "nghi_duong" | "trang_trai_nha_vuon" | "bds_khac";

export interface DetailedFilterState {
  timeRange: TimeRange;
  inventoryScope: InventoryScope;
  leadStatus: LeadStatus;
  itemType: ItemType;
  metricMode: MetricMode;
  propertyType: PropertyType;
}

export interface InventoryDetailedItem {
  type: string; // Chung cu, Biet thu...
  sell: { count: number; value: number; fee: number };
  rent: { count: number; value: number; fee: number };
}

export interface DashboardData {
  kpi: KPIItem[];
  funnel: FunnelStage[];
  leadSources: LeadSource[];
  revenue: RevenueData[];
  inventory: InventoryCategory[];
  inventoryDetailed: InventoryDetailedItem[];
}

export interface FilterState {
  period: string;
  status: string;
}

// --- TABLE SPECIFIC TYPES ---
export type OwnerBucket = "chinh_chu" | "moi_gioi" | "cho_ban" | "chua_ban" | "da_coc" | "da_ban" | "huy_hang";

export interface CellMetric {
  count: number;        // SL
  valueBillion: number; // Giá trị (tỷ)
  feeBillion: number;   // Phí (tỷ)
}

export interface RowData {
  id: string;
  propertyType: string; // Label display
  propertyKey: PropertyType | string; // Key for filtering
  byBucket: Record<OwnerBucket, CellMetric>;
}

import React, { useMemo, useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent, Select, Button, TooltipWrapper } from './ui';
import { DetailedFilterState, ItemType, MetricMode, PropertyType, RowData, OwnerBucket, CellMetric } from '../types';
import { RotateCcw, ArrowUpDown, X, ExternalLink, Info } from 'lucide-react';
import { cn, formatNumber, formatCurrencyTy } from '../utils';

// --- MOCK DATA GENERATOR ---
const BUCKETS: { key: OwnerBucket; label: string }[] = [
  { key: "chinh_chu", label: "Chính Chủ" },
  { key: "moi_gioi", label: "Môi Giới" },
  { key: "cho_ban", label: "Chờ Bán" },
  { key: "chua_ban", label: "Chưa Bán" },
  { key: "da_coc", label: "Đã Cọc" },
  { key: "da_ban", label: "Đã Bán" },
  { key: "huy_hang", label: "Hủy Hàng" },
];

const PROPERTY_LABELS = [
  "Chung Cư", "Liên Kế", "Biệt Thự", "Nhà Riêng", "Đất Nền",
  "Biệt thự nhà vườn - Trang trại", "Ki-ốt & Sàn thương mại", "Khách sạn nghỉ dưỡng", "BĐS Khác"
];

const generateMockRow = (label: string, id: string): RowData => {
  const byBucket = {} as Record<OwnerBucket, CellMetric>;
  BUCKETS.forEach(b => {
    // Random data generation logic
    const baseCount = Math.floor(Math.random() * 200);
    byBucket[b.key] = {
      count: baseCount,
      valueBillion: baseCount * (Math.random() * 5 + 2), // ~2-7 ty per unit avg
      feeBillion: baseCount * (Math.random() * 5 + 2) * 0.02 // 2% fee
    };
  });

  // Mapping label to key for filtering
  let key = 'bds_khac';
  if (label === "Chung Cư") key = 'chung_cu';
  else if (label === "Liên Kế") key = 'lien_ke';
  else if (label === "Biệt Thự") key = 'biet_thu';
  else if (label === "Nhà Riêng") key = 'nha_rieng';
  else if (label === "Đất Nền") key = 'dat_nen';
  else if (label.includes("Trang trại")) key = 'trang_trai_nha_vuon';
  else if (label.includes("Ki-ốt")) key = 'shophouse_kiosk';
  else if (label.includes("nghỉ dưỡng")) key = 'nghi_duong';

  return { id, propertyType: label, propertyKey: key, byBucket };
};

const MOCK_DATA: RowData[] = PROPERTY_LABELS.map((label, idx) => generateMockRow(label, `row-${idx}`));

// --- HELPERS ---

const computeRowTotal = (row: RowData): CellMetric => {
  return Object.values(row.byBucket).reduce((acc, curr) => ({
    count: acc.count + curr.count,
    valueBillion: acc.valueBillion + curr.valueBillion,
    feeBillion: acc.feeBillion + curr.feeBillion
  }), { count: 0, valueBillion: 0, feeBillion: 0 });
};

const computeGrandTotal = (rows: RowData[]): Record<OwnerBucket | 'tong', CellMetric> => {
  const result = {} as Record<OwnerBucket | 'tong', CellMetric>;

  // Initialize
  BUCKETS.forEach(b => result[b.key] = { count: 0, valueBillion: 0, feeBillion: 0 });
  result['tong'] = { count: 0, valueBillion: 0, feeBillion: 0 };

  rows.forEach(row => {
    const rowTotal = computeRowTotal(row);
    // Add to grand total of 'tong' column
    result['tong'].count += rowTotal.count;
    result['tong'].valueBillion += rowTotal.valueBillion;
    result['tong'].feeBillion += rowTotal.feeBillion;

    // Add to specific buckets
    BUCKETS.forEach(b => {
      const cell = row.byBucket[b.key];
      result[b.key].count += cell.count;
      result[b.key].valueBillion += cell.valueBillion;
      result[b.key].feeBillion += cell.feeBillion;
    });
  });

  return result;
};

interface InventoryDetailTableCardProps {
  filters: DetailedFilterState;
  setFilters: React.Dispatch<React.SetStateAction<DetailedFilterState>>;
}

export const InventoryDetailTableCard: React.FC<InventoryDetailTableCardProps> = ({ filters, setFilters }) => {
  const [sortConfig, setSortConfig] = useState<{ key: 'count' | 'value' | 'fee'; direction: 'asc' | 'desc' }>({ key: 'value', direction: 'desc' });
  const [popoverData, setPopoverData] = useState<{ x: number, y: number, data: CellMetric, title: string } | null>(null);

  // --- FILTER & SORT LOGIC ---
  const filteredRows = useMemo(() => {
    let rows = [...MOCK_DATA];

    // Filter by Property Type
    if (filters.propertyType !== 'tat_ca') {
      rows = rows.filter(r => r.propertyKey === filters.propertyType);
    }

    // Mock ItemType filter effect (just strictly reducing numbers for demo)
    if (filters.itemType === 'ban') {
       rows = rows.map(r => ({ ...r, byBucket: Object.fromEntries(Object.entries(r.byBucket).map(([k, v]) => [k, { ...v, count: Math.ceil(v.count * 0.7) }])) as any }));
    } else if (filters.itemType === 'cho_thue') {
       rows = rows.map(r => ({ ...r, byBucket: Object.fromEntries(Object.entries(r.byBucket).map(([k, v]) => [k, { ...v, count: Math.ceil(v.count * 0.3) }])) as any }));
    }

    // Sort based on TOTAL column
    rows.sort((a, b) => {
      const totalA = computeRowTotal(a);
      const totalB = computeRowTotal(b);

      let valA = totalA.valueBillion;
      let valB = totalB.valueBillion;

      if (sortConfig.key === 'count') { valA = totalA.count; valB = totalB.count; }
      if (sortConfig.key === 'fee') { valA = totalA.feeBillion; valB = totalB.feeBillion; }

      return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
    });

    return rows;
  }, [filters, sortConfig]);

  const grandTotal = useMemo(() => computeGrandTotal(filteredRows), [filteredRows]);

  const handleSort = () => {
    setSortConfig(prev => ({
      key: filters.metricMode === 'so_luong' ? 'count' : filters.metricMode === 'phi' ? 'fee' : 'value',
      direction: prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const handleResetFilters = () => {
    setFilters(prev => ({
        ...prev,
        itemType: 'tat_ca',
        metricMode: 'so_luong',
        propertyType: 'tat_ca'
    }));
  };

  const handleCellClick = (e: React.MouseEvent, metric: CellMetric, context: string) => {
    e.stopPropagation();
    const rect = (e.target as HTMLElement).getBoundingClientRect();
    setPopoverData({
        x: rect.left,
        y: rect.bottom + window.scrollY,
        data: metric,
        title: context
    });
  };

  // --- RENDERERS ---

  const renderCellContent = (metric: CellMetric, isTotal = false, contextLabel: string) => {
    const isCountMode = filters.metricMode === 'so_luong';
    const isValueMode = filters.metricMode === 'gia_tri';
    const isFeeMode = filters.metricMode === 'phi';

    // Opacity Logic based on mode
    const opacityLine1 = isCountMode ? 'opacity-100 font-bold' : 'opacity-70';
    const opacityLine2 = isValueMode ? 'opacity-100 font-bold' : 'opacity-80';
    const opacityLine3 = isFeeMode ? 'opacity-100 font-bold' : 'opacity-60';

    return (
      <div className="flex flex-col items-end gap-0.5 group/cell">
         {/* Line 1: Count */}
         <TooltipWrapper content={`${contextLabel} - Số lượng: ${formatNumber(metric.count)} căn`}>
            <span 
                onClick={(e) => handleCellClick(e, metric, contextLabel)}
                className={cn(
                    "text-sm cursor-pointer hover:underline decoration-indigo-400 decoration-2 underline-offset-2 transition-all",
                    isTotal ? "text-indigo-800" : "text-indigo-600",
                    opacityLine1
                )}
            >
                {formatNumber(metric.count)}
            </span>
         </TooltipWrapper>

         {/* Line 2: Value */}
         <div className={cn("text-xs text-slate-900 whitespace-nowrap", opacityLine2)}>
            {formatNumber(metric.valueBillion)} <span className="text-[10px] text-slate-500 font-normal">tỷ</span>
         </div>

         {/* Line 3: Fee */}
         <div className={cn("text-[10px] text-slate-500 whitespace-nowrap", opacityLine3)}>
            {formatNumber(metric.feeBillion)} <span className="text-[9px]">tỷ</span>
         </div>
      </div>
    );
  };

  return (
    <Card className="w-full shadow-md border-slate-200 overflow-hidden relative">
      {/* --- HEADER --- */}
      <CardHeader className="bg-white border-b border-slate-100 py-4 px-6 flex flex-col xl:flex-row items-start xl:items-center justify-between gap-4">
         <div>
            <CardTitle className="text-lg text-slate-800">Chi Tiết Hàng Hóa & Giá Trị</CardTitle>
            <div className="flex items-center gap-4 mt-2 text-[11px] text-slate-500 font-medium">
                <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-indigo-500"/>Dòng 1: Số lượng</span>
                <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-slate-800"/>Dòng 2: Giá trị (tỷ)</span>
                <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-slate-400"/>Dòng 3: Phí (tỷ)</span>
            </div>
         </div>

         {/* Inline Filters */}
         <div className="flex flex-wrap items-center gap-3">
            <Select 
                placeholder="Loại Hàng"
                value={filters.itemType}
                onChange={(v) => setFilters(prev => ({...prev, itemType: v as any}))}
                options={[
                    {label: "Tất cả", value: "tat_ca"},
                    {label: "BĐS Bán", value: "ban"},
                    {label: "BĐS Cho Thuê", value: "cho_thue"},
                ]}
                className="w-[130px]"
            />
            <Select 
                placeholder="Chế độ xem"
                value={filters.metricMode}
                onChange={(v) => setFilters(prev => ({...prev, metricMode: v as any}))}
                options={[
                    {label: "SL (Số lượng)", value: "so_luong"},
                    {label: "Giá Trị (tỷ)", value: "gia_tri"},
                    {label: "Phí (tỷ)", value: "phi"},
                ]}
                className="w-[140px]"
            />
            <Select 
                placeholder="Loại BĐS"
                value={filters.propertyType}
                onChange={(v) => setFilters(prev => ({...prev, propertyType: v as any}))}
                options={[{label: "Tất cả", value: "tat_ca"}, ...PROPERTY_LABELS.map(l => ({label: l, value: MOCK_DATA.find(r => r.propertyType === l)?.propertyKey || 'tat_ca'}))]}
                className="w-[180px]"
                showClear
            />
            <Button variant="outline" size="icon" onClick={handleResetFilters} title="Reset bộ lọc">
                <RotateCcw size={16} />
            </Button>
         </div>
      </CardHeader>

      {/* --- TABLE CONTENT --- */}
      <CardContent className="p-0 overflow-hidden relative">
         <div className="overflow-x-auto custom-scrollbar w-full pb-2">
            <table className="w-full text-right border-collapse min-w-[1200px]">
                <thead className="bg-slate-50 text-slate-500 font-semibold text-[11px] uppercase tracking-wider sticky top-0 z-20 shadow-sm">
                    <tr>
                        <th className="sticky left-0 bg-slate-50 z-30 px-4 py-3 text-left border-r border-slate-200 min-w-[180px] shadow-[4px_0_8px_-4px_rgba(0,0,0,0.05)]">
                            Loại BĐS
                        </th>
                        {BUCKETS.map(b => (
                            <th key={b.key} className="px-3 py-3 border-r border-slate-100 min-w-[100px]">
                                {b.label}
                            </th>
                        ))}
                        <th 
                            onClick={handleSort}
                            className="sticky right-0 bg-indigo-50/80 z-30 px-4 py-3 text-indigo-900 border-l border-indigo-100 min-w-[120px] cursor-pointer hover:bg-indigo-100 transition-colors shadow-[-4px_0_8px_-4px_rgba(0,0,0,0.05)]"
                        >
                            <div className="flex items-center justify-end gap-1">
                                TỔNG
                                <ArrowUpDown size={12} className={cn("opacity-50", sortConfig.direction === 'asc' && "rotate-180")} />
                            </div>
                        </th>
                    </tr>
                </thead>

                <tbody className="text-sm divide-y divide-slate-100 bg-white">
                    {filteredRows.map((row, idx) => {
                        const total = computeRowTotal(row);
                        const isHighlighted = false; // logic for highlight specific row if needed

                        return (
                            <tr key={row.id} className="group hover:bg-slate-50 transition-colors">
                                {/* Sticky Left Label */}
                                <td className="sticky left-0 bg-white group-hover:bg-slate-50 z-20 px-4 py-3 text-left font-semibold text-slate-700 border-r border-slate-200 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.05)] whitespace-nowrap">
                                    {row.propertyType}
                                </td>

                                {/* Data Buckets */}
                                {BUCKETS.map(b => (
                                    <td key={b.key} className="px-3 py-2 border-r border-slate-100 align-top">
                                        {renderCellContent(row.byBucket[b.key], false, `${row.propertyType} - ${b.label}`)}
                                    </td>
                                ))}

                                {/* Sticky Right Total */}
                                <td className="sticky right-0 bg-indigo-50/30 group-hover:bg-indigo-50/60 z-20 px-4 py-2 border-l border-indigo-100 shadow-[-4px_0_8px_-4px_rgba(0,0,0,0.05)] align-top">
                                    {renderCellContent(total, true, `${row.propertyType} - TỔNG`)}
                                </td>
                            </tr>
                        )
                    })}
                </tbody>

                {/* --- FOOTER GRAND TOTAL --- */}
                <tfoot className="bg-indigo-50/50 sticky bottom-0 z-20 border-t-2 border-indigo-100">
                    <tr>
                        <td className="sticky left-0 bg-indigo-50 z-30 px-4 py-3 text-left font-bold text-indigo-900 border-r border-indigo-200 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.05)]">
                            TỔNG CỘNG
                        </td>
                        {BUCKETS.map(b => (
                            <td key={b.key} className="px-3 py-3 border-r border-indigo-200/50 align-top">
                                {renderCellContent(grandTotal[b.key], true, `Tổng - ${b.label}`)}
                            </td>
                        ))}
                        <td className="sticky right-0 bg-indigo-100 z-30 px-4 py-3 border-l border-indigo-200 shadow-[-4px_0_8px_-4px_rgba(0,0,0,0.05)] align-top">
                            {renderCellContent(grandTotal['tong'], true, `TỔNG TOÀN BỘ`)}
                        </td>
                    </tr>
                </tfoot>
            </table>
         </div>

         {/* --- POPOVER MOCK --- */}
         {popoverData && (
             <>
                 <div className="fixed inset-0 z-40" onClick={() => setPopoverData(null)} />
                 <div 
                    className="fixed z-50 bg-white rounded-xl shadow-2xl border border-slate-200 p-4 w-64 animate-in zoom-in-95 duration-200"
                    style={{ top: Math.min(popoverData.y + 10, window.innerHeight - 200), left: Math.min(popoverData.x - 100, window.innerWidth - 300) }}
                 >
                    <div className="flex justify-between items-start mb-3">
                        <h4 className="text-sm font-bold text-slate-800 line-clamp-2">{popoverData.title}</h4>
                        <button onClick={() => setPopoverData(null)} className="text-slate-400 hover:text-slate-600"><X size={14}/></button>
                    </div>
                    <div className="space-y-2 bg-slate-50 p-3 rounded-lg mb-3">
                        <div className="flex justify-between text-xs">
                            <span className="text-slate-500">Số lượng:</span>
                            <span className="font-bold text-indigo-600">{formatNumber(popoverData.data.count)}</span>
                        </div>
                        <div className="flex justify-between text-xs">
                            <span className="text-slate-500">Giá trị:</span>
                            <span className="font-semibold text-slate-800">{formatCurrencyTy(popoverData.data.valueBillion)}</span>
                        </div>
                        <div className="flex justify-between text-xs">
                            <span className="text-slate-500">Phí MG:</span>
                            <span className="font-medium text-slate-600">{formatCurrencyTy(popoverData.data.feeBillion)}</span>
                        </div>
                    </div>
                    <Button variant="primary" size="sm" className="w-full text-xs h-8 gap-1">
                        <ExternalLink size={12} /> Xem danh sách
                    </Button>
                 </div>
             </>
         )}
      </CardContent>
    </Card>
  );
};

import React from 'react';
import { Card, CardContent, CardHeader, CardTitle, Select, Skeleton } from './ui';
