// --- Custom Select (Shadcn-like) ---
export interface SelectOption {
  value: string;
  label: string;
}

interface SelectProps {
  value: string;
  onChange: (value: string) => void;
  options: SelectOption[];
  label?: string;
  placeholder?: string;
  className?: string;
  disabled?: boolean;
  loading?: boolean;
  error?: boolean;
  showClear?: boolean;
}

export const Select: React.FC<SelectProps> = ({ 
  value, onChange, options, label, placeholder = "Chọn...", 
  className, disabled, loading, error, showClear 
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  // Close on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const selectedOption = options.find(opt => opt.value === value);

  const handleSelect = (val: string) => {
    if (val !== value) onChange(val);
    setIsOpen(false);
  };

  const handleClear = (e: React.MouseEvent) => {
    e.stopPropagation();
    onChange(options[0]?.value || ""); // Reset to first or empty
  };

  return (
    <div className={cn("relative inline-block text-left min-w-[160px]", className)} ref={containerRef}>
      {/* Label */}
      {label && <label className="block text-xs font-semibold text-slate-500 mb-1.5 ml-1">{label}</label>}

      {/* Trigger */}
      <button
        type="button"
        onClick={() => !disabled && !loading && setIsOpen(!isOpen)}
        disabled={disabled || loading}
        className={cn(
          "w-full flex items-center justify-between rounded-xl border bg-white px-3 py-2 text-sm font-medium shadow-sm transition-all focus:outline-none focus:ring-2 focus:ring-indigo-500/20",
          error ? "border-rose-300 text-rose-600 focus:border-rose-500" : "border-slate-200 text-slate-700 focus:border-indigo-500 hover:border-indigo-300",
          (disabled || loading) && "opacity-60 cursor-not-allowed bg-slate-50",
          isOpen && "ring-2 ring-indigo-500/20 border-indigo-500"
        )}
      >
        <span className={cn("truncate mr-2", !selectedOption && "text-slate-400")}>
          {loading ? "Đang tải..." : (selectedOption ? selectedOption.label : placeholder)}
        </span>
        <div className="flex items-center gap-1">
           {loading ? (
             <Loader2 size={14} className="animate-spin text-slate-400" />
           ) : (
             <>
               {showClear && value !== options[0]?.value && !disabled && (
                 <div onClick={handleClear} className="p-0.5 rounded-full hover:bg-slate-100 text-slate-400 hover:text-slate-600 mr-1 transition-colors">
                    <X size={12} />
                 </div>
               )}
               <ChevronDown size={16} className={cn("text-slate-400 transition-transform duration-200", isOpen && "rotate-180")} />
             </>
           )}
        </div>
      </button>

      {/* Dropdown Menu */}
      {isOpen && !disabled && (
        <div className="absolute z-50 mt-1 w-full min-w-[180px] origin-top-right rounded-xl border border-slate-100 bg-white shadow-lg shadow-slate-200/50 ring-1 ring-black ring-opacity-5 focus:outline-none animate-in fade-in zoom-in-95 duration-100 max-h-[300px] overflow-y-auto custom-scrollbar">
          <div className="p-1 space-y-0.5">
            {options.length === 0 ? (
                <div className="px-3 py-2.5 text-xs text-slate-400 text-center italic">Không có dữ liệu</div>
            ) : (
                options.map((opt) => (
                <button
                    key={opt.value}
                    onClick={() => handleSelect(opt.value)}
                    className={cn(
                    "group flex w-full items-center justify-between rounded-lg px-3 py-2 text-sm transition-colors",
                    value === opt.value 
                        ? "bg-indigo-50 text-indigo-700 font-semibold" 
                        : "text-slate-700 hover:bg-slate-50 hover:text-slate-900"
                    )}
                >
                    <span className="truncate">{opt.label}</span>
                    {value === opt.value && <Check size={14} strokeWidth={2.5} className="text-indigo-600 ml-2" />}
                </button>
                ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};


