export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [currentRoute, setCurrentRoute] = useState('dashboard'); // Route state

  // Dashboard Specific States
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<DashboardData | null>(null);
  const [filters, setFilters] = useState<DetailedFilterState>(DEFAULT_FILTERS);
  const [activeTab, setActiveTab] = useState('overview');
  const [highlightedSource, setHighlightedSource] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  // Handle Route Changes
  useEffect(() => {
    const handleRouteChange = (e: CustomEvent) => {
        setCurrentRoute(e.detail);
    };
    window.addEventListener('routeChange' as any, handleRouteChange);
    return () => window.removeEventListener('routeChange' as any, handleRouteChange);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const result = await getDashboardData(filters);
      setData(result);
      const now = new Date();
      setLastUpdated(now.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}));
    } catch (error) {
      console.error("Failed to load data", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (currentRoute === 'dashboard') {
        fetchData();
    }
  }, [currentRoute, filters.timeRange, filters.inventoryScope, filters.propertyType, filters.leadStatus]);

  const handleReset = () => {
    setFilters(DEFAULT_FILTERS);
    setHighlightedSource(null);
  };

  const renderTrend = (type: 'positive' | 'negative' | 'neutral', value?: string) => {
    if (!value) return null;
    let Icon = Minus;
    let colorClass = "text-slate-500 bg-slate-100";
    if (type === 'positive') { Icon = TrendingUp; colorClass = "text-emerald-700 bg-emerald-50 border-emerald-100"; } 
    else if (type === 'negative') { Icon = TrendingDown; colorClass = "text-rose-700 bg-rose-50 border-rose-100"; }
    return <div className={cn("flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-bold border", colorClass)}><Icon size={12} />{value}</div>;
  };

  // --- RENDER CONTENT BASED ON ROUTE ---
  const renderContent = () => {
      if (currentRoute === 'leads') {
          return <LeadList />;
      }

      // Default Dashboard
      return (
        <>
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-2">
            <div>
                <h1 className="text-2xl md:text-3xl font-extrabold text-slate-800 tracking-tight">Tổng Quan Hoạt Động</h1>
                <div className="flex items-center gap-2 mt-2">
                    <Badge variant="indigo" className="font-normal text-[11px] py-0.5">Real-time Data</Badge>
                    <span className="text-slate-400 text-sm">•</span>
                    <span className="text-slate-500 text-sm">Cập nhật: {lastUpdated}</span>
                </div>
            </div>
            <div className="flex items-center gap-3">
                <Button variant="outline" className="hidden sm:flex gap-2 text-slate-600 border-slate-200 shadow-sm bg-white"><Share2 size={16} /> Chia sẻ</Button>
                <Button variant="primary" className="gap-2 shadow-lg shadow-indigo-200 hover:shadow-indigo-300"><Download size={16} /> Xuất Báo Cáo</Button>
            </div>
            </div>

            {/* GLOBAL FILTER BAR */}
            <div className="sticky top-0 z-30 bg-[#F8FAFC]/95 backdrop-blur-md py-4 -my-4 border-b border-slate-200/60 flex flex-col xl:flex-row items-start xl:items-center justify-between gap-4 transition-all shadow-[0_4px_20px_-10px_rgba(0,0,0,0.05)] px-1 -mx-1">
            <div className="flex items-center gap-4 w-full xl:w-auto overflow-x-auto pb-1 xl:pb-0 no-scrollbar">
                <Tabs 
                activeTab={activeTab} 
                onChange={setActiveTab} 
                tabs={[
                    { id: 'overview', label: 'Tổng Quan' }, 
                    { id: 'inventory_detailed', label: 'Hàng Hóa Chi Tiết' }
                ]} 
                />
                <div className="h-6 w-px bg-slate-300 mx-2 hidden sm:block"></div>

                <div className="flex items-center gap-3">
                    <Select 
                    label="Thời gian"
                    value={filters.timeRange} 
                    onChange={(val) => setFilters(prev => ({ ...prev, timeRange: val as any }))} 
                    options={TIME_RANGE_OPTIONS}
                    />
                    <Select 
                    label="Phạm vi"
                    value={filters.inventoryScope}
                    onChange={(val) => setFilters(prev => ({ ...prev, inventoryScope: val as any }))}
                    options={INVENTORY_SCOPE_OPTIONS}
                    />
                </div>
            </div>

            <div className="flex flex-wrap items-center gap-3 w-full xl:w-auto justify-end">
                <Select 
                label="Trạng Thái Lead"
                value={filters.leadStatus} 
                onChange={(val) => setFilters(prev => ({ ...prev, leadStatus: val as any }))} 
                options={LEAD_STATUS_OPTIONS}
                className="min-w-[180px]"
                />
                <TooltipWrapper content="Khôi phục bộ lọc mặc định">
                <Button variant="ghost" size="icon" onClick={handleReset} className="mt-5 h-10 w-10 text-slate-400 hover:text-indigo-600 bg-white border border-slate-200 shadow-sm">
                    <RotateCcw size={16} />
                </Button>
                </TooltipWrapper>
            </div>
            </div>

            {/* KPI Grid (Always visible but data changes) */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4 lg:gap-5">
            {loading ? Array(6).fill(0).map((_, i) => (
                <Card key={i} className="h-36 border-transparent bg-white"><CardContent className="h-full p-5"><Skeleton className="h-full w-full" /></CardContent></Card>
            )) : data?.kpi.map((item) => {
                const { icon: Icon, color, bg } = getKPIConfig(item.id);
                return (
                <TooltipWrapper key={item.id} content={item.tooltip}>
                <Card className="hover:-translate-y-1 h-full">
                    <CardContent className="p-5 flex flex-col justify-between h-full">
                    <div className="flex justify-between items-start mb-3">
                        <div className={cn("p-2.5 rounded-xl", bg, color)}><Icon size={20} /></div>
                        {renderTrend(item.changeType, item.changeValue)}
                    </div>
                    <div>
                        <h4 className="text-slate-500 text-xs font-semibold uppercase tracking-wide truncate">{item.label}</h4>
                        <div className="flex items-baseline gap-1 mt-1">
                        <span className="text-2xl font-extrabold text-slate-800 tracking-tight">
                            {item.unit === 'tỷ' ? formatCurrencyTy(item.value).replace(' tỷ', '') : formatNumber(item.value)}
                        </span>
                        {item.unit && <span className="text-xs font-bold text-slate-500">{item.unit}</span>}
                        </div>
                    </div>
                    </CardContent>
                </Card>
                </TooltipWrapper>
            )})}
            </div>

            {/* --- VIEW SWITCHER --- */}
            {activeTab === 'overview' ? (
            <>
                {/* Overview: Funnel + Source */}
                <div className="grid grid-cols-1 xl:grid-cols-12 gap-6 lg:gap-8">
                    <div className="xl:col-span-8">
                        <FunnelCard 
                            data={data?.funnel || []} 
                            isLoading={loading}
                            selectedStage={filters.leadStatus !== 'tat_ca' && filters.leadStatus !== 'that_bai' ? filters.leadStatus as FunnelStageKey : undefined}
                            onSelectStage={(key) => setFilters(prev => ({ ...prev, leadStatus: prev.leadStatus === key ? 'tat_ca' : key }))}
                        />
                    </div>
                    <Card className="xl:col-span-4 flex flex-col">
                        <CardHeader>
                            <CardTitle>Nguồn Khách Hàng</CardTitle>
                            <Button variant="ghost" size="icon" className="h-8 w-8 text-slate-400 hover:bg-slate-100 rounded-full"><MoreHorizontal size={16}/></Button>
                        </CardHeader>
                        <CardContent className="flex-1 flex flex-col p-0 bg-slate-50/30">
                            <div className="flex-1 min-h-[240px] mt-6 px-4">
                            {loading ? <Skeleton className="h-full w-full" /> : (
                                <SourcePieChart 
                                    data={data?.leadSources || []} 
                                    onSelect={(name) => setHighlightedSource(name === highlightedSource ? null : name)} 
                                />
                            )}
                            </div>
                            {!loading && data && (
                            <div className="mt-4 border-t border-slate-100 max-h-[220px] overflow-y-auto custom-scrollbar bg-white rounded-b-2xl">
                                <table className="w-full text-sm text-left">
                                <thead className="bg-slate-50 text-slate-500 font-semibold sticky top-0 z-10">
                                    <tr>
                                    <th className="px-6 py-3 text-[10px] uppercase tracking-wider text-slate-400">Kênh</th>
                                    <th className="px-6 py-3 text-right text-[10px] uppercase tracking-wider text-slate-400">Lead</th>
                                    <th className="px-6 py-3 text-right text-[10px] uppercase tracking-wider text-slate-400">Deal</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {data.leadSources.map((source) => (
                                    <tr key={source.name} className={cn("transition-all cursor-pointer group hover:bg-slate-50", highlightedSource && highlightedSource !== source.name && "opacity-30 blur-[0.5px]", highlightedSource === source.name && "bg-indigo-50/70")} onClick={() => setHighlightedSource(highlightedSource === source.name ? null : source.name)}>
                                        <td className="px-6 py-3 font-medium flex items-center gap-2.5 text-slate-700">
                                            <span className="w-2.5 h-2.5 rounded-full ring-2 ring-white shadow-sm" style={{ backgroundColor: source.color }} />
                                            {source.name}
                                        </td>
                                        <td className="px-6 py-3 text-right text-slate-600 font-medium">{source.value}</td>
                                        <td className="px-6 py-3 text-right text-slate-900 font-bold">{source.deals}</td>
                                    </tr>
                                    ))}
                                </tbody>
                                </table>
                            </div>
                            )}
                        </CardContent>
                    </Card>
                </div>

                {/* Overview: Revenue + Simple Inventory */}
                <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 lg:gap-8 pb-12">
                    <Card>
                        <CardHeader>
                            <CardTitle><div className="p-2 bg-emerald-50 rounded-lg text-emerald-600 mr-1"><Banknote size={18}/></div>Dòng Tiền & Doanh Thu</CardTitle>
                        </CardHeader>
                        <CardContent className="bg-slate-50/30">
                            {loading ? <Skeleton className="h-[320px] w-full" /> : <RevenueLineChart data={data?.revenue || []} />}
                        </CardContent>
                    </Card>
                    <Card>
                        <CardHeader>
                            <CardTitle><div className="p-2 bg-amber-50 rounded-lg text-amber-600 mr-1"><Building size={18}/></div>Cơ Cấu Giỏ Hàng</CardTitle>
                            <Badge variant="warning">Tồn kho thấp</Badge>
                        </CardHeader>
                        <CardContent className="bg-slate-50/30">
                            {loading ? <Skeleton className="h-[320px] w-full" /> : <InventoryBarChart data={data?.inventory || []} />}
                        </CardContent>
                    </Card>
                </div>
            </>
            ) : (
                <InventoryTab 
                    data={data?.inventoryDetailed || []} 
                    filters={filters} 
                    setFilters={setFilters} 
                    isLoading={loading} 
                />
            )}
        </>
      );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans text-slate-900 flex selection:bg-indigo-100 selection:text-indigo-900">
      <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} currentRoute={currentRoute} />

      <main className={cn("flex-1 transition-all duration-300 ease-in-out min-h-screen flex flex-col", sidebarOpen ? "ml-[260px]" : "ml-[80px]")}>
        <div className="p-6 lg:p-8 space-y-8 max-w-[1920px] mx-auto w-full">
            {renderContent()}
        </div>
      </main>
    </div>
  );
}

payload.text:
Bạn là senior front-end UI engineer + UX. Hãy build popup “Tạo Lead” dạng wizard (multi-step modal) cho hệ thống BĐS Vuông. UI giống wireframe.

TECH
- Next.js 14 (App Router) + TypeScript + Tailwind + shadcn/ui + lucide-react
- FE-only + mock data, không cần backend thật
- A11y đầy đủ (focus trap trong modal, tab/enter/esc)

ENTRYPOINT
- Trên màn /leads có nút “+ Tạo Lead” => mở modal “Tạo Lead”.

MODAL SHELL (BẮT BUỘC)
- Modal centered, width ~900–1000px desktop; mobile full-screen.
- Header trái: title “Tạo Lead”
- Header phải: nút close (X)
- Ngay dưới header là Step Tabs (clickable nhưng chỉ cho phép click vào step đã hoàn thành):
  1) Thông tin Lead & Liên hệ
  2) Khu vực & Ngân sách
  3) Nguồn Lead & phân bổ
  4) Ghi chú & tác vụ
(Tên step đúng như wireframe) :contentReference[oaicite:0]{index=0}

- Footer sticky:
  - Left: button “Hủy”
  - Right: button “Tiếp” (ở step 1–3) / “Tạo Lead” (ở step cuối)
(Ở step 1 có “Hủy / Tiếp” đúng wireframe) :contentReference[oaicite:1]{index=1}

========================
STEP 1 — THÔNG TIN LEAD & LIÊN HỆ
========================
Fields (đúng label + required):
- Họ tên Lead / Khách hàng * (placeholder “VD: Nguyễn Văn A”) :contentReference[oaicite:2]{index=2}
- Email (placeholder “nguyenvana@gmail.com”) :contentReference[oaicite:3]{index=3}
- Nhu cầu chính * (Select “Chọn nhu cầu”) :contentReference[oaicite:4]{index=4}
  Options: Mua / Thuê / Ký Gửi Bán / Ký Gửi Cho Thuê :contentReference[oaicite:5]{index=5}
- Loại BĐS quan tâm * (Select “Chọn loại BĐS”) :contentReference[oaicite:6]{index=6}
  Options: Chung Cư, Liền Kề, Biệt Thự, Nhà Riêng, Đất Nền, Biệt thự nhà vườn - Trang trại, Ki-ot & Sàn thương mại, Khách sạn nghỉ dưỡng, BĐS Khác :contentReference[oaicite:7]{index=7}
- Giới tính (Select default “Không xác định”)
  Options: Không xác định / Nam / Nữ :contentReference[oaicite:8]{index=8}
- Số điện thoại * (mask “09xx xxx xxx”) :contentReference[oaicite:9]{index=9}

VALIDATION STEP 1
- Required: Họ tên, Nhu cầu chính, Loại BĐS quan tâm, Số điện thoại.
- Phone uniqueness check (mock): khi blur SĐT nếu trùng => hiển thị inline error: “Số điện thoại này đã có trong hệ thống” :contentReference[oaicite:10]{index=10}
  (UX gợi ý: có thể disable “Tiếp” + show CTA “Mở Lead hiện có” — nếu bạn muốn, implement như 1 optional flow.)

========================
STEP 2 — KHU VỰC & NGÂN SÁCH
========================
Fields (đúng wireframe):
- Bất Động Sản: Select “Chọn BĐS trong list Hàng Hóa” :contentReference[oaicite:11]{index=11}
- Nhóm Dự Án/Khu vực: readonly “Tự động theo BĐS” :contentReference[oaicite:12]{index=12}
- Tỉnh / Thành phố *: Select “Chọn Tỉnh/Thành” :contentReference[oaicite:13]{index=13}
- Xã/Phường *: Select “Chọn Xã/Phường” :contentReference[oaicite:14]{index=14}
- Thuộc Dự án / Khu vực (text) placeholder “VD: KĐT Dương Nội, K Park,...” :contentReference[oaicite:15]{index=15}
- Diện Tích Tối Thiểu * (number) placeholder “VD: 80 m²” :contentReference[oaicite:16]{index=16}
- Diện Tích Tối Đa * (number) placeholder “VD: 150 m²” :contentReference[oaicite:17]{index=17}
- Địa Chỉ Cụ Thể (text) placeholder “VD: Nhà số 3 ngách…” :contentReference[oaicite:18]{index=18}
- Ngân sách tối thiểu * (currency) placeholder “VD: 12,7 Tỷ” :contentReference[oaicite:19]{index=19}
- Ngân sách tối đa * (currency) placeholder “VD: 12,7 Tỷ” :contentReference[oaicite:20]{index=20}
- Hình thức thanh toán (text) placeholder “VD: Vay bank/ Tiền mặt/Hỗn Hợp” :contentReference[oaicite:21]{index=21}
- Thời gian Giao Dịch mong muốn: Select default “Không xác định” :contentReference[oaicite:22]{index=22}
  Options: Không xác định / Trong 1 tháng / 1 → 3 tháng / 3 → 6 tháng / Trên 6 tháng :contentReference[oaicite:23]{index=23}

BUSINESS NOTE (từ sticky note wireframe)
- Khi chọn “BĐS có sẵn” (từ list Hàng Hóa), các trường bên dưới sẽ auto-fill (implement mock autofill). (Note nằm ở phần sticky note trong file.) :contentReference[oaicite:24]{index=24}

VALIDATION STEP 2
- Required: Tỉnh/Thành phố, Xã/Phường, Diện tích min/max, Ngân sách min/max.
- Rule: min ≤ max cho Diện tích và Ngân sách; show inline error rõ ràng.

========================
STEP 3 — NGUỒN LEAD & PHÂN BỔ
========================
Fields:
- Nguồn Lead *: Select “Chọn nguồn Lead” :contentReference[oaicite:25]{index=25}
- Chuyên Viên phụ trách *: Select “Chọn Chuyên Viên” :contentReference[oaicite:26]{index=26}
- Trạng thái Lead *: Select “Chọn Trạng thái” :contentReference[oaicite:27]{index=27}
  Options: Lead Mới, Đang Chăm, Hẹn Xem Nhà, Deal Mở, Đàm Phán, Đặt Cọc, Giao Dịch Hoàn Tất, Thất Bại :contentReference[oaicite:28]{index=28}
- Chi tiết nguồn (text) placeholder “VD: CTV A giới thiệu, …” :contentReference[oaicite:29]{index=29}

BUSINESS NOTE (từ sticky note wireframe)
- Nếu chọn trạng thái từ “Hẹn Xem Nhà” trở đi thì Lead sẽ được move sang Deals (thể hiện bằng 1 confirm modal “Chuyển Lead sang Deals?” + mock redirect). (Note nằm ở sticky note trong file.) :contentReference[oaicite:30]{index=30}

VALIDATION STEP 3
- Required: Nguồn Lead, Chuyên viên phụ trách, Trạng thái Lead.

========================
STEP 4 — GHI CHÚ & TÁC VỤ
========================
Fields:
- Ghi chú (textarea) placeholder “VD: Anh A muốn căn góc….” :contentReference[oaicite:31]{index=31}
- Tác vụ: table/list có nút “+ Thêm mới”
  - Mỗi row gồm:
    - Tác vụ (text) (ví dụ “Gọi lại cho khách”, “Tư vấn mã #1234”… ) :contentReference[oaicite:32]{index=32}
    - Người giao (Select) (lấy từ list user, wireframe minh hoạ “Trịnh Trung Hiếu”) :contentReference[oaicite:33]{index=33}
    - Thời gian (datetime) (format: yyyy.mm.dd hh:mm:ss) :contentReference[oaicite:34]{index=34}
  - Có checkbox chọn row (optional) + delete row.

FOOTER STEP 4
- Buttons: “Hủy” và “Tạo Lead”
- Submit => toast “Tạo Lead thành công” + close modal + refresh list.

========================
TRẠNG THÁI UI (BẮT BUỘC)
========================
- Loading: skeleton cho form/step (delay mock 400–800ms mỗi lần chuyển step)
- Error: toast “Không tải được dữ liệu” (mock random 5%)
- Unsaved changes: nếu user bấm Hủy/close khi đã nhập => confirm “Bạn có muốn thoát? Dữ liệu chưa được lưu.”
- Stepper rule: không cho sang step tiếp theo nếu step hiện tại invalid.

OUTPUT
- Trả code chạy được:
  - components/leads/CreateLeadWizardModal.tsx
  - data/mockUsers.ts, data/mockLeadSources.ts, data/mockProperties.ts
  - types.ts cho LeadDraft + TaskItem + enums
- Có ví dụ integration trong /leads page: button “+ Tạo Lead” mở modal.

