            {children}
            <div className="pointer-events-none absolute bottom-[105%] left-1/2 -translate-x-1/2 whitespace-nowrap rounded-lg bg-slate-800 px-3 py-1.5 text-xs font-medium text-white opacity-0 shadow-lg transition-all group-hover:opacity-100 group-hover:bottom-[115%] z-50">
                {content}
