export interface Deal {
  id: string; // DEAL-001
  leadId?: string;
  customerId: string;
  customerName: string;
  phone: string;
  need: NeedType;
  propertyType: string; // mapped from propertyType labels
  area: string;
  budgetTy: number;
  source: LeadSourceType;
  assignee: string;
  stage: DealStage;
  createdAt: string;
  updatedAt: string;
  expectedCloseDate?: string;
}

export interface DealFilterState {
  quickRange: "7_ngay" | "thang_nay" | "tuy_chinh";
  dateRange: { from: string | null, to: string | null }; // ISO strings
  search: string;
  source: LeadSourceType;
  stage: DealStage;
  assignee: string;
  need: NeedType;
  propertyType: PropertyType;
  area: string;
  budget: BudgetRange;
  page: number;
  pageSize: number;
}

export interface DealDashboardData {
  deals: Deal[];
  totalCount: number;
  kpi: {
    totalDeals: number;
    newThisWeek: number;
    wonDeals: number;
    conversionRate: number; // % won / total
  }
}

// --- WIZARD TYPES (LEAD) ---
export interface TaskItem {
  id: string;
  task: string;
  assignee: string;
  deadline: string;
}

export interface LeadDraft {
  // Step 1
  name: string;
  email: string;
  need: string;
  propertyTypeInterest: string;
  gender: string;
  phone: string;

  // Step 2
  refPropertyId: string; // ID of existing inventory
  projectArea: string; // Readonly
  city: string;
  ward: string;
  projectDetail: string; // KĐT Dương Nội...
  areaMin: string; // number as string for input
  areaMax: string;
  address: string;
  budgetMin: string;
  budgetMax: string;
  paymentMethod: string;
  timeframe: string;

  // Step 3
  source: string;
  assignee: string;
  status: string;
  sourceDetail: string;

  // Step 4
  note: string;
  tasks: TaskItem[];
}

// --- DEAL CREATION WIZARD TYPES ---
export type DealLinkMode = "from_lead" | "direct";
export type DealExpectedCloseWindow = "khong_xac_dinh" | "trong_1_thang" | "1_3_thang" | "3_6_thang" | "tren_6_thang";

export interface DealTaskItem {
  id: string;
  title: string;
  assigneeId: string;
  assigneeName: string;
  dueAt: string; // ISO
}

export interface DealDraft {
  // liên kết lead (optional)
  linkMode: DealLinkMode;
  leadId?: string;

  // khách hàng
  customerName: string;
  phone: string;
  email?: string;
  gender?: "khong_xac_dinh" | "nam" | "nu";
  need: string; // NeedType but allow string for form
  propertyType: string;

  // bđs & điều kiện giao dịch
  propertyId?: string;          // chọn từ list hàng hóa
  projectOrAreaAuto?: string;    // tự động theo BĐS
  province?: string;
  ward?: string;
  areaText?: string;            // “Thuộc Dự án/Khu vực…”
  addressDetail?: string;

  minArea?: string;             // number as string input
  maxArea?: string;
  minBudgetTy?: string;         // number as string input
  maxBudgetTy?: string;

  // deal-specific fields:
  expectedCloseWindow?: DealExpectedCloseWindow;
  paymentMethodNote?: string;   // “Vay bank/Tiền mặt/Hỗn hợp…”
  depositAmountTy?: string;     // number as string
  dealValueTy?: string;         // number as string

  // nguồn & phân bổ
  dealSource: string;
  assigneeId: string;
  dealStage: string; // DealStage
  sourceDetail?: string;

  // notes & tasks
  note?: string;
  tasks: DealTaskItem[];
}

// --- PIPELINE TYPES ---
export type PipelineStageKey = 
  | "lead_moi" 
  | "dang_cham" 
  | "hen_xem_nha" 
  | "deal_mo" 
  | "dam_phan" 
  | "dat_coc" 
  | "gd_hoan_tat" 
