      <div className="w-full">
         {label && <label className="block text-xs font-semibold text-slate-500 mb-1.5 ml-1">{label} {props.required && <span className="text-rose-500">*</span>}</label>}
         <div className="relative">
            {icon && (
            <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
                {icon}
            </div>
            )}
            <input
            ref={ref}
            className={cn(
                "flex h-10 w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm ring-offset-white file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-slate-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500/20 focus-visible:border-indigo-500 disabled:cursor-not-allowed disabled:opacity-50 transition-all",
                icon && "pl-10",
                error ? "border-rose-300 focus-visible:border-rose-500 focus-visible:ring-rose-500/20" : "",
                className
            )}
            {...props}
            />
        </div>
        {error && <p className="mt-1 text-xs text-rose-500 font-medium ml-1">{error}</p>}
      </div>
    );
  }
);
Input.displayName = "Input";

