// --- Pagination ---
interface PaginationProps {
  page: number;
  total: number;
  size: number;
  onChange: (page: number) => void;
}

export const Pagination: React.FC<PaginationProps> = ({ page, total, size, onChange }) => {
  const totalPages = Math.ceil(total / size);
  if (totalPages <= 1) return null;

  return (
    <div className="flex items-center gap-1">
      <Button 
        variant="outline" 
        size="icon" 
        className="h-8 w-8 rounded-lg"
        onClick={() => onChange(Math.max(1, page - 1))}
        disabled={page === 1}
      >
        <ChevronLeft size={16} />
      </Button>
      <div className="text-sm font-medium px-2 text-slate-600">
         Trang <span className="text-slate-900">{page}</span> / {totalPages}
      </div>
      <Button 
        variant="outline" 
        size="icon" 
        className="h-8 w-8 rounded-lg"
        onClick={() => onChange(Math.min(totalPages, page + 1))}
        disabled={page === totalPages}
      >
        <ChevronRight size={16} />
      </Button>
    </div>
  );
}

// --- Toast (Simplified) ---
export const toast = (message: string, type: 'success' | 'error' = 'success') => {
    const el = document.createElement('div');
    el.className = cn(
        "fixed top-4 right-4 z-[9999] px-4 py-3 rounded-xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-5 duration-300 font-medium text-sm",
        type === 'success' ? "bg-white border-l-4 border-emerald-500 text-slate-800" : "bg-white border-l-4 border-rose-500 text-slate-800"
    );
    el.innerHTML = `
        <span class="${type === 'success' ? 'text-emerald-500' : 'text-rose-500'}">
            ${type === 'success' ? '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="20 6 9 17 4 12"></polyline></svg>' : '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>'}
        </span>
        ${message}
    `;
    document.body.appendChild(el);
    setTimeout(() => {
        el.classList.add('opacity-0');
        setTimeout(() => el.remove(), 300);
    }, 3000);
}

