                            </div>
                            <div className="p-6">
                                {loading ? <Skeleton className="h-[320px] w-full" /> : <InventoryBarChart data={data?.inventory || []} />}
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </>
            ) : (
                /* INVENTORY DETAILED TAB */
                <InventoryTab 
                    data={data?.inventoryDetailed || []} 
                    filters={filters} 
                    setFilters={setFilters} 
                    isLoading={loading} 
                />
            )}
        </>
      );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans text-slate-900 flex selection:bg-indigo-100 selection:text-indigo-900">
      <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} currentRoute={currentRoute} />

      <main className={cn("flex-1 transition-all duration-300 ease-in-out min-h-screen flex flex-col", sidebarOpen ? "ml-[260px]" : "ml-[80px]")}>
        <div className="p-6 lg:p-8 space-y-6 max-w-[1920px] mx-auto w-full">
            {renderContent()}
        </div>
      </main>
