                                            <div className="flex items-center justify-center gap-1">
                                                {lead.status === 'hen_xem_nha' && (
                                                    <TooltipWrapper content="Xem Deal">
                                                        <Button size="icon" className="h-7 w-7 text-emerald-600 bg-emerald-50 hover:bg-emerald-100 hover:text-emerald-700" onClick={() => handleNavToDeal(lead.id)}>
                                                            <ArrowRight size={14} />
