                                                    <Button size="icon" variant="ghost" className="h-7 w-7 text-indigo-600 hover:bg-indigo-50"><Eye size={14}/></Button>
                                                </TooltipWrapper>
                                                <TooltipWrapper content="Xóa">
                                                    <Button size="icon" variant="ghost" className="h-7 w-7 text-rose-500 hover:bg-rose-50"><Trash2 size={14}/></Button>
                                                </TooltipWrapper>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* --- FOOTER PAGINATION --- */}
                <div className="p-4 border-t border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-4 bg-slate-50/50">
                    <div className="flex items-center gap-3 text-xs text-slate-600">
                        <span>Hiển thị</span>
                        <Select 
                            value={filters.pageSize.toString()} 
                            options={[{label:'10', value:'10'}, {label:'20', value:'20'}, {label:'50', value:'50'}]}
                            onChange={(v) => setFilters(p => ({...p, pageSize: parseInt(v), page: 1}))}
                            className="w-[60px] h-8"
                        />
                        <span>kết quả: <b>{Math.min((filters.page - 1) * filters.pageSize + 1, data?.totalCount || 0)} - {Math.min(filters.page * filters.pageSize, data?.totalCount || 0)}</b> trong <b>{data?.totalCount}</b></span>
                    </div>
                    <Pagination 
                        page={filters.page} 
                        total={data?.totalCount || 0} 
                        size={filters.pageSize} 
                        onChange={(p) => setFilters(prev => ({...prev, page: p}))}
                    />
                </div>
                </>
             )}
          </CardContent>
       </Card>
    </div>
  );
};

