                    <div className="space-y-2 bg-slate-50 p-3 rounded-lg mb-3">
                        <div className="flex justify-between text-xs">
                            <span className="text-slate-500">Số lượng:</span>
                            <span className="font-bold text-indigo-600">{formatNumber(popoverData.data.count)}</span>
                        </div>
                        <div className="flex justify-between text-xs">
                            <span className="text-slate-500">Giá trị:</span>
                            <span className="font-semibold text-slate-800">{formatCurrencyTy(popoverData.data.valueBillion)}</span>
                        </div>
                        <div className="flex justify-between text-xs">
                            <span className="text-slate-500">Phí MG:</span>
                            <span className="font-medium text-slate-600">{formatCurrencyTy(popoverData.data.feeBillion)}</span>
                        </div>
                    </div>
                    <Button variant="primary" size="sm" className="w-full text-xs h-8 gap-1">
                        <ExternalLink size={12} /> Xem danh sách
                    </Button>
                 </div>
             </>
         )}
      </CardContent>
    </Card>
  );
};

import React, { useEffect, useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { 
  Card, CardContent, CardHeader, CardTitle, 
  Button, Select, Tabs, Badge, Skeleton, TooltipWrapper 
} from './components/ui';
import { 
  SourcePieChart, RevenueLineChart, InventoryBarChart 
} from './components/charts';
import { FunnelCard } from './components/FunnelCard';
import { InventoryTab } from './components/InventoryTab';
import { LeadList } from './components/LeadList'; 
import { DealList } from './components/DealList'; 
import { PipelinePage } from './components/PipelinePage'; 
import { getDashboardData } from './data';
import { DashboardData, DetailedFilterState, FunnelStageKey } from './types';
import { formatNumber, formatCurrencyTy, cn } from './utils';
import { 
  RotateCcw, Download, Share2, MoreHorizontal,
  Users, Briefcase, CheckCircle2, Banknote, Building, Percent,
  ArrowUpRight, ArrowDownRight, Minus, Filter
} from 'lucide-react';

// --- CONSTANTS ---
const TIME_RANGE_OPTIONS = [
    { label: '7 Ngày Qua', value: '7_ngay_gan_nhat' },
    { label: '30 Ngày Qua', value: '30_ngay_gan_nhat' },
    { label: 'Tháng Này', value: 'thang_nay' },
    { label: 'Quý Này', value: 'quy_nay' },
];

const INVENTORY_SCOPE_OPTIONS = [
    { label: 'Tất cả Kho', value: 'tat_ca_hang_hoa' },
    { label: 'Hàng Bán', value: 'hang_ban' },
    { label: 'Hàng Thuê', value: 'hang_thue' },
    { label: 'Đã Chốt', value: 'da_chot' },
];

const LEAD_STATUS_OPTIONS = [
    { label: 'Tất Cả Trạng Thái', value: 'tat_ca' },
    { label: 'Lead Mới', value: 'lead_moi' },
    { label: 'Đang Chăm', value: 'dang_cham' },
    { label: 'Hẹn Xem', value: 'hen_xem_nha' },
    { label: 'Deal Mở', value: 'deal_mo' },
    { label: 'Đàm Phán', value: 'dam_phan' },
];

const DEFAULT_FILTERS: DetailedFilterState = {
    timeRange: "7_ngay_gan_nhat",
    inventoryScope: "tat_ca_hang_hoa",
    leadStatus: "tat_ca",
    itemType: "tat_ca",
    metricMode: "so_luong",
    propertyType: "tat_ca"
};

const getKPIConfig = (id: string) => {
  switch(id) {
    case '1': return { icon: Users, color: 'text-blue-600', bg: 'bg-blue-50/50 border-blue-100' };
    case '2': return { icon: Briefcase, color: 'text-violet-600', bg: 'bg-violet-50/50 border-violet-100' };
    case '3': return { icon: CheckCircle2, color: 'text-emerald-600', bg: 'bg-emerald-50/50 border-emerald-100' };
    case '4': return { icon: Banknote, color: 'text-amber-600', bg: 'bg-amber-50/50 border-amber-100' };
    case '5': return { icon: Building, color: 'text-indigo-600', bg: 'bg-indigo-50/50 border-indigo-100' };
    case '6': return { icon: Percent, color: 'text-rose-600', bg: 'bg-rose-50/50 border-rose-100' };
    default: return { icon: Users, color: 'text-slate-600', bg: 'bg-slate-50 border-slate-200' };
  }
}

export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [currentRoute, setCurrentRoute] = useState('dashboard');

  // Dashboard Specific States
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<DashboardData | null>(null);
  const [filters, setFilters] = useState<DetailedFilterState>(DEFAULT_FILTERS);
  const [activeTab, setActiveTab] = useState('overview');
  const [highlightedSource, setHighlightedSource] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  useEffect(() => {
    const handleRouteChange = (e: CustomEvent) => {
        setCurrentRoute(e.detail);
    };
    window.addEventListener('routeChange' as any, handleRouteChange);
    return () => window.removeEventListener('routeChange' as any, handleRouteChange);
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const result = await getDashboardData(filters);
      setData(result);
      const now = new Date();
      setLastUpdated(now.toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'}));
    } catch (error) {
      console.error("Failed to load data", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (currentRoute === 'dashboard') {
        fetchData();
    }
  }, [currentRoute, filters.timeRange, filters.inventoryScope, filters.propertyType, filters.leadStatus]);

  const handleReset = () => {
    setFilters(DEFAULT_FILTERS);
    setHighlightedSource(null);
  };

  const renderTrend = (type: 'positive' | 'negative' | 'neutral', value?: string) => {
    if (!value) return null;
    let Icon = Minus;
    let colorClass = "text-slate-500";
    if (type === 'positive') { Icon = ArrowUpRight; colorClass = "text-emerald-600"; } 
    else if (type === 'negative') { Icon = ArrowDownRight; colorClass = "text-rose-600"; }

    return (
        <div className={cn("flex items-center gap-0.5 text-[11px] font-bold", colorClass)}>
            <Icon size={12} />
            {value}
        </div>
    );
  };

  const renderContent = () => {
      if (currentRoute === 'leads') return <LeadList />;
      if (currentRoute === 'deals') return <DealList />;
      if (currentRoute === 'pipeline') return <PipelinePage />;

      // --- DEFAULT DASHBOARD ---
      return (
        <>
            {/* Header Row */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 mb-2">
                <div>
                    <h1 className="text-2xl md:text-3xl font-extrabold text-slate-800 tracking-tight">Tổng Quan Hoạt Động</h1>
                    <div className="flex items-center gap-2 mt-2">
                        <Badge variant="indigo" className="font-normal text-[10px] py-0.5">Live</Badge>
                        <span className="text-slate-400 text-xs">•</span>
                        <span className="text-slate-500 text-xs">Cập nhật: {lastUpdated}</span>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <Button variant="outline" size="sm" className="hidden sm:flex bg-white h-8 text-xs border-slate-200"><Share2 size={14} className="mr-2"/> Chia sẻ</Button>
                    <Button variant="primary" size="sm" className="h-8 text-xs shadow-md shadow-indigo-200"><Download size={14} className="mr-2"/> Xuất Báo Cáo</Button>
                </div>
            </div>

            {/* STICKY HEADER: Tabs + Filters Stacked */}
            <div className="sticky top-0 z-30 bg-[#F8FAFC]/95 backdrop-blur-md pt-2 pb-3 mb-4 border-b border-slate-200/80 shadow-[0_4px_20px_-8px_rgba(0,0,0,0.08)] -mx-6 px-6 md:-mx-8 md:px-8 transition-all">
                <div className="flex flex-col items-center gap-2 max-w-[1920px] mx-auto w-full">

                    {/* Row 1: Tabs (Centered) */}
                    <div className="flex justify-center w-full">
                        <Tabs 
                            activeTab={activeTab} 
                            onChange={setActiveTab} 
                            tabs={[
                                { id: 'overview', label: 'Tổng Quan' }, 
                                { id: 'inventory_detailed', label: 'Hàng Hóa Chi Tiết' }
                            ]} 
                            className="h-8 text-xs bg-slate-100/80 p-0.5"
                        />
                    </div>

                    {/* Row 2: Filters (Centered Row) */}
                    <div className="flex flex-wrap items-center justify-center gap-2 w-full">
                         <div className="hidden md:flex items-center gap-1.5 text-[10px] font-bold text-slate-400 uppercase tracking-wider mr-1">
                             <Filter size={10} /> Bộ lọc:
                         </div>
                         <Select 
                            value={filters.timeRange} 
                            onChange={(val) => setFilters(prev => ({ ...prev, timeRange: val as any }))} 
                            options={TIME_RANGE_OPTIONS}
                            className="w-[110px] h-8 text-xs bg-white shadow-sm border-slate-200"
                        />
                        <Select 
                            value={filters.inventoryScope}
                            onChange={(val) => setFilters(prev => ({ ...prev, inventoryScope: val as any }))}
                            options={INVENTORY_SCOPE_OPTIONS}
                            className="w-[110px] h-8 text-xs bg-white shadow-sm border-slate-200"
                        />
                         <Select 
                            value={filters.leadStatus} 
                            onChange={(val) => setFilters(prev => ({ ...prev, leadStatus: val as any }))} 
                            options={LEAD_STATUS_OPTIONS}
                            className="w-[120px] h-8 text-xs bg-white shadow-sm border-slate-200"
                        />

                        <div className="h-4 w-px bg-slate-300 mx-1 hidden sm:block" />

                        <TooltipWrapper content="Khôi phục mặc định">
                             <Button 
                                variant="ghost" 
                                size="sm" 
                                onClick={handleReset} 
                                className="h-8 px-2 text-xs text-rose-500 hover:text-rose-600 hover:bg-rose-50 gap-1"
                            >
                                <RotateCcw size={12} /> Reset
                            </Button>
                        </TooltipWrapper>
                    </div>
                </div>
            </div>

            {/* KPI Grid */}
            <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-3">
            {loading ? Array(6).fill(0).map((_, i) => (
                <Card key={i} className="h-28 border-transparent bg-white shadow-sm"><CardContent className="h-full p-4"><Skeleton className="h-full w-full" /></CardContent></Card>
            )) : data?.kpi.map((item) => {
                const { icon: Icon, color, bg } = getKPIConfig(item.id);
                return (
                <TooltipWrapper key={item.id} content={item.tooltip}>
                <Card className="hover:-translate-y-1 hover:shadow-md transition-all h-full border border-slate-200/60 shadow-sm">
                    <CardContent className="p-4 flex flex-col justify-between h-full">
                        <div className="flex justify-between items-start mb-2">
                            <span className="text-[11px] font-bold text-slate-500 uppercase tracking-wide truncate max-w-[80%]">{item.label}</span>
                            <div className={cn("p-1.5 rounded-lg border", bg, color)}>
                                <Icon size={14} strokeWidth={2.5} />
                            </div>
                        </div>

                        <div>
                            <div className="flex items-baseline gap-1.5">
                                <span className="text-2xl font-extrabold text-slate-800 tracking-tight leading-none">
                                    {item.unit === 'tỷ' ? formatCurrencyTy(item.value).replace(' tỷ', '') : formatNumber(item.value)}
                                </span>
                                {item.unit && <span className="text-xs font-bold text-slate-400 self-end mb-0.5">{item.unit}</span>}
                            </div>

                            <div className="flex items-center mt-2 gap-2">
                                <div className="bg-slate-50 px-1.5 py-0.5 rounded border border-slate-100">
                                    {renderTrend(item.changeType, item.changeValue)}
                                </div>
                                <span className="text-[10px] text-slate-400 font-medium">so với kỳ trước</span>
                            </div>
                        </div>
                    </CardContent>
                </Card>
                </TooltipWrapper>
            )})}
            </div>

            {/* --- DASHBOARD CONTENT SWITCHER --- */}
            {activeTab === 'overview' ? (
                // 1. OVERVIEW VIEW
                <div className="space-y-6 lg:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                    {/* Funnel + Sources */}
                    <div className="grid grid-cols-1 xl:grid-cols-12 gap-6 lg:gap-8">
                        <div className="xl:col-span-8">
                            <FunnelCard 
                                data={data?.funnel || []} 
                                isLoading={loading}
                                selectedStage={filters.leadStatus !== 'tat_ca' && filters.leadStatus !== 'that_bai' ? filters.leadStatus as FunnelStageKey : undefined}
                                onSelectStage={(key) => setFilters(prev => ({ ...prev, leadStatus: prev.leadStatus === key ? 'tat_ca' : key }))}
                            />
                        </div>
                        <Card className="xl:col-span-4 flex flex-col shadow-sm border border-slate-200">
                            <CardContent className="flex-1 flex flex-col p-0">
                                <div className="p-5 border-b border-slate-100 flex justify-between items-center">
                                    <h3 className="font-bold text-slate-800 text-lg">Nguồn Lead</h3>
                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-slate-400"><MoreHorizontal size={16}/></Button>
                                </div>
                                <div className="flex-1 min-h-[240px] px-4 mt-4">
                                {loading ? <Skeleton className="h-full w-full" /> : (
                                    <SourcePieChart 
                                        data={data?.leadSources || []} 
                                        onSelect={(name) => setHighlightedSource(name === highlightedSource ? null : name)} 
                                    />
                                )}
                                </div>
                                {!loading && data && (
                                <div className="border-t border-slate-100 max-h-[220px] overflow-y-auto custom-scrollbar bg-slate-50/30">
                                    <table className="w-full text-sm text-left">
                                    <thead className="bg-slate-50 text-slate-500 font-semibold sticky top-0 z-10 shadow-sm">
                                        <tr>
                                        <th className="px-6 py-3 text-[10px] uppercase tracking-wider text-slate-400">Kênh</th>
                                        <th className="px-6 py-3 text-right text-[10px] uppercase tracking-wider text-slate-400">Lead</th>
                                        <th className="px-6 py-3 text-right text-[10px] uppercase tracking-wider text-slate-400">Deal</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-100">
                                        {data.leadSources.map((source) => (
                                        <tr key={source.name} className={cn("transition-all cursor-pointer group hover:bg-white", highlightedSource && highlightedSource !== source.name && "opacity-30 blur-[0.5px]", highlightedSource === source.name && "bg-indigo-50/70")} onClick={() => setHighlightedSource(highlightedSource === source.name ? null : source.name)}>
                                            <td className="px-6 py-3 font-medium flex items-center gap-2.5 text-slate-700">
                                                <span className="w-2.5 h-2.5 rounded-full ring-2 ring-white shadow-sm" style={{ backgroundColor: source.color }} />
                                                {source.name}
                                            </td>
                                            <td className="px-6 py-3 text-right text-slate-600 font-medium">{source.value}</td>
                                            <td className="px-6 py-3 text-right text-slate-900 font-bold">{source.deals}</td>
                                        </tr>
                                        ))}
                                    </tbody>
                                    </table>
                                </div>
                                )}
                            </CardContent>
                        </Card>
                    </div>

                    {/* Revenue + Simple Inventory */}
                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 lg:gap-8 pb-12">
                        <Card className="shadow-sm border border-slate-200">
                            <CardContent className="p-0">
                                <div className="p-5 border-b border-slate-100">
                                    <h3 className="font-bold text-slate-800 text-lg flex items-center gap-2">
                                        <div className="p-1.5 bg-emerald-50 rounded text-emerald-600"><Banknote size={16}/></div>
                                        Dòng Tiền & Doanh Thu
                                    </h3>
                                </div>
                                <div className="p-6">
                                    {loading ? <Skeleton className="h-[320px] w-full" /> : <RevenueLineChart data={data?.revenue || []} />}
                                </div>
                            </CardContent>
                        </Card>
                        <Card className="shadow-sm border border-slate-200">
                            <CardContent className="p-0">
                                <div className="p-5 border-b border-slate-100 flex items-center justify-between">
                                    <h3 className="font-bold text-slate-800 text-lg flex items-center gap-2">
                                        <div className="p-1.5 bg-amber-50 rounded text-amber-600"><Building size={16}/></div>
                                        Cơ Cấu Giỏ Hàng
                                    </h3>
                                    <Badge variant="warning">Tồn kho thấp</Badge>
                                </div>
                                <div className="p-6">
                                    {loading ? <Skeleton className="h-[320px] w-full" /> : <InventoryBarChart data={data?.inventory || []} />}
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                </div>
            ) : (
                // 2. INVENTORY DETAILED VIEW
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                     <InventoryTab 
                        data={data?.inventoryDetailed || []} 
                        filters={filters} 
                        setFilters={setFilters} 
                        isLoading={loading} 
                    />
                </div>
            )}
        </>
      );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans text-slate-900 flex selection:bg-indigo-100 selection:text-indigo-900">
      <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} currentRoute={currentRoute} />

      <main className={cn("flex-1 transition-all duration-300 ease-in-out min-h-screen flex flex-col", sidebarOpen ? "ml-[260px]" : "ml-[80px]")}>
        <div className="p-6 lg:p-8 space-y-6 max-w-[1920px] mx-auto w-full relative">
            {renderContent()}
        </div>
      </main>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { cn } from '../utils';
import { ChevronDown, Check, Loader2, X, ChevronLeft, ChevronRight, Search, CheckSquare, Square } from 'lucide-react';

// --- Card ---
export const Card: React.FC<{ children?: React.ReactNode; className?: string; onClick?: () => void }> = ({ children, className, onClick }) => (
  <div 
    onClick={onClick}
    className={cn(
      "bg-white rounded-xl border border-slate-200 shadow-sm transition-all duration-200",
      className
    )}
  >
    {children}
  </div>
);

export const CardHeader: React.FC<{ children?: React.ReactNode; className?: string }> = ({ children, className }) => (
  <div className={cn("px-6 py-4 border-b border-slate-100 flex items-center justify-between", className)}>{children}</div>
);

export const CardTitle: React.FC<{ children?: React.ReactNode; className?: string }> = ({ children, className }) => (
  <h3 className={cn("font-semibold text-slate-900 text-base flex items-center gap-2", className)}>{children}</h3>
);

export const CardContent: React.FC<{ children?: React.ReactNode; className?: string }> = ({ children, className }) => (
  <div className={cn("p-6", className)}>{children}</div>
);

// --- Button ---
interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'outline' | 'ghost' | 'destructive' | 'secondary';
  size?: 'sm' | 'md' | 'lg' | 'icon';
}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant = 'primary', size = 'md', ...props }, ref) => {
    const variants = {
      primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-sm",
      secondary: "bg-slate-800 text-white hover:bg-slate-900",
      outline: "border border-slate-200 bg-white text-slate-700 hover:bg-slate-50 hover:border-slate-300 shadow-sm",
      ghost: "text-slate-600 hover:bg-slate-100 hover:text-indigo-600",
      destructive: "bg-rose-50 text-rose-600 hover:bg-rose-100",
    };
    const sizes = {
      sm: "h-8 px-3 text-xs",
      md: "h-10 px-4 text-sm",
      lg: "h-12 px-6 text-base",
      icon: "h-10 w-10 p-2 flex items-center justify-center rounded-lg",
    };

    return (
      <button
        ref={ref}
        className={cn(
          "inline-flex items-center justify-center rounded-lg font-medium transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500 disabled:pointer-events-none disabled:opacity-50 active:scale-95",
          variants[variant],
          sizes[size],
          className
        )}
        {...props}
      />
    );
  }
);
Button.displayName = "Button";

// --- Input ---
interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  icon?: React.ReactNode;
  label?: string;
  error?: string;
}

export const Input = React.forwardRef<HTMLInputElement, InputProps>(
  ({ className, icon, label, error, ...props }, ref) => {
    return (
      <div className="w-full">
         {label && <label className="block text-xs font-semibold text-slate-600 mb-1.5">{label} {props.required && <span className="text-rose-500">*</span>}</label>}
         <div className="relative">
            {icon && (
            <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
                {icon}
            </div>
            )}
            <input
            ref={ref}
            className={cn(
                "flex h-10 w-full rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm ring-offset-white file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-slate-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500/20 focus-visible:border-indigo-500 disabled:cursor-not-allowed disabled:opacity-50 transition-all",
                icon && "pl-10",
                error ? "border-rose-300 focus-visible:border-rose-500 focus-visible:ring-rose-500/20" : "",
                className
            )}
            {...props}
            />
        </div>
        {error && <p className="mt-1 text-xs text-rose-500 font-medium ml-1">{error}</p>}
      </div>
    );
  }
);
Input.displayName = "Input";

// --- Textarea ---
interface TextareaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
    label?: string;
}

export const Textarea = React.forwardRef<HTMLTextAreaElement, TextareaProps>(
    ({ className, label, ...props }, ref) => {
        return (
            <div className="w-full">
                 {label && <label className="block text-xs font-semibold text-slate-600 mb-1.5">{label} {props.required && <span className="text-rose-500">*</span>}</label>}
                 <textarea
                    ref={ref}
                    className={cn(
                        "flex min-h-[80px] w-full rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm ring-offset-white placeholder:text-slate-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500/20 focus-visible:border-indigo-500 disabled:cursor-not-allowed disabled:opacity-50 transition-all resize-none",
                        className
                    )}
                    {...props}
                />
            </div>
        )
    }
);
Textarea.displayName = "Textarea";

// --- Checkbox ---
export const Checkbox = ({ checked, onChange, className }: { checked?: boolean, onChange?: (val: boolean) => void, className?: string }) => {
    return (
        <button 
            type="button" 
            onClick={() => onChange?.(!checked)}
            className={cn("text-slate-400 hover:text-indigo-600 transition-colors", checked && "text-indigo-600", className)}
        >
            {checked ? <CheckSquare size={18} /> : <Square size={18} />}
        </button>
    )
}

// --- Badge ---
export const Badge: React.FC<{ children?: React.ReactNode; variant?: 'success' | 'danger' | 'neutral' | 'warning' | 'indigo' | 'outline'; className?: string }> = ({ children, variant = 'neutral', className }) => {
  const styles = {
    success: "bg-emerald-50 text-emerald-700 border border-emerald-100",
    danger: "bg-rose-50 text-rose-700 border border-rose-100",
    warning: "bg-amber-50 text-amber-700 border border-amber-100",
